export interface DomRelativePosition {
  top: number;
  left: number;
  right: number;
  bottom: number;
  width: number;
  height: number;
  parentHeight: number;
  parentWidth: number;
}
/**
 * Checks if an element is at least partially visible within its scrollable parent
 * @param element - The element to check visibility for
 * @param scrollableParent - The scrollable container element
 * @returns `true` if the element is at least partially visible
 */
export const getElementRelativePosition = (
  element: HTMLElement,
  scrollableParent: HTMLElement,
): DomRelativePosition => {
  const parentRect = scrollableParent.getBoundingClientRect();
  const elementRect = element.getBoundingClientRect();

  const relativeDimensions: DomRelativePosition = {
    top: elementRect.top - parentRect.top,
    left: elementRect.left - parentRect.left,
    right: elementRect.right - parentRect.left,
    bottom: elementRect.bottom - parentRect.top,
    width: elementRect.width,
    height: elementRect.height,
    parentHeight: parentRect.height,
    parentWidth: parentRect.width,
  };

  return relativeDimensions;
};
