import type { Env } from "../../library/build-scripts/types.ts";
type ClientEnv = Omit<Env, "SIGNUP_FORM_ACTION">;

const env: ClientEnv = {
  API_URL: Deno.env.get("API_URL")!,
  PRODUCTION_MODE: Deno.env.get("PRODUCTION_MODE")! === "true",
  DEV_MODE: Deno.env.get("DEV_MODE")! === "true",
};

Object.entries(env).forEach(([key, value]) => {
  if (value == null) {
    throw new Error(`\`${key}\` is not defined`);
  }
});

export const { API_URL, DEV_MODE, PRODUCTION_MODE } = env;
