import {
  debounce,
  ensureAllElementsNotNull,
  plausibleSendEvent,
  prefersReducedMotion,
  processDomElementOnce,
  querySelector,
  querySelectorAll,
} from "../clientScript/clientDependencies.ts";

const timerTime = 8000;

function setCurrent(this: HTMLElement, isCurrent: boolean) {
  if (isCurrent) {
    this.setAttribute("aria-current", "true");
    this.setAttribute("aria-disabled", "true");
    this.setAttribute("disabled", "true");
  } else {
    this.removeAttribute("aria-current");
    this.removeAttribute("aria-disabled");
    this.removeAttribute("disabled");
  }
}
type SetCurrent = typeof setCurrent;

processDomElementOnce("carousel-wrapper", (carouselWrapper) => {
  const elements = ensureAllElementsNotNull(
    querySelector<HTMLUListElement>(".controls", { parent: carouselWrapper }),
    querySelectorAll<HTMLButtonElement & { setCurrent: SetCurrent }>("button", {
      parent: querySelector(".navigation", { parent: carouselWrapper }),
    }),
    querySelector<HTMLUListElement>(".slidesList"),
    querySelector<HTMLDivElement>("live-region", { parent: carouselWrapper }),
  );
  if (elements === null) {
    console.error("Carousel: Missing control elements");
    return;
  }
  const [playControlsContainer, navigationDotsRaw, slider, liveRegion] =
    elements;

  const subElements = ensureAllElementsNotNull(
    querySelector<HTMLButtonElement>("button.previous", {
      parent: playControlsContainer,
    }),
    querySelector<HTMLButtonElement>("button.next", {
      parent: playControlsContainer,
    }),
    querySelector<HTMLInputElement>("input[type='checkbox']", {
      parent: playControlsContainer,
    }),
    querySelector<HTMLLabelElement>("label", { parent: playControlsContainer }),
    querySelectorAll<HTMLLIElement>("li", { parent: slider }),
  );

  if (subElements === null) {
    console.error("Carousel: Missing play control elements");
    return;
  }

  const slideButtons = navigationDotsRaw.map((btn) => {
    btn.setCurrent = setCurrent;
    const targetIndex = parseInt(btn.dataset.for || "", 10);
    if (isNaN(targetIndex)) {
      console.warn(`Carousel: Missing target slide for button`, btn);
      return btn;
    }
    btn.addEventListener("click", () => {
      plausibleSendEvent("Carousel navigation dot", {
        props: { index: controller.currentSlide, targetIndex },
      });
      controller.updateSlider(targetIndex);
      if (!pauseRequested) {
        startTimer();
      }
    });
    return btn;
  });

  const [previousButton, nextButton, pauseInput, pauseLabel, slides] =
    subElements;

  const controller = (() => {
    let currentSlide = Math.ceil(slider.scrollLeft / slider.offsetWidth) %
      slides.length;

    const nextSlide = () => updateSlider((currentSlide + 1) % slides.length);

    const prevSlide = () =>
      updateSlider((currentSlide - 1 + slides.length) % slides.length);

    const updateSlider = (nextSlide: number) => {
      if (nextSlide === currentSlide) {
        return;
      }
      slideButtons.forEach((btn, index) => btn.setCurrent(index === nextSlide));
      currentSlide = nextSlide;
      slider.scrollLeft = slider.offsetWidth * currentSlide;
      if (liveRegion) {
        liveRegion.textContent = `Item ${currentSlide + 1} of ${slides.length}`;
      }
    };

    return {
      nextSlide,
      prevSlide,
      updateSlider,
      get currentSlide() {
        return currentSlide;
      },
    };
  })();

  let pauseInterval: number | null = null;
  let pauseRequested = false;

  const nextSlideFromTimer = () => {
    plausibleSendEvent("Carousel auto-next", {
      props: { index: controller.currentSlide },
    });
    controller.nextSlide();
  };

  const startTimer = () => {
    clearInterval(pauseInterval as number);
    if (pauseRequested) {
      return;
    }
    pauseInterval = setInterval(nextSlideFromTimer, timerTime);
    carouselWrapper.style.setProperty("--timer-animation-name", "none");
    carouselWrapper.style.setProperty("--timer-time", `${timerTime}ms`);
    // The animation would not be restarted on mobile when clicking around and
    // updating the CSS, and you'd get the light purple progress animation
    // getting out of sync with the carousel. This is used to force restart the
    // animation
    void carouselWrapper.offsetWidth;
    carouselWrapper.style.setProperty(
      "--timer-animation-name",
      "carouselProgressAnimation",
    );
    if (pauseInput) {
      pauseInput.checked = false;
    }
  };

  const stopTimer = () => {
    carouselWrapper.style.setProperty("--timer-time", "0ms");
    carouselWrapper.style.setProperty("--timer-animation-name", "none");
    clearInterval(pauseInterval as number);
    pauseInterval = null;
    if (pauseInput) {
      pauseInput.checked = true;
    }
  };

  previousButton.addEventListener("click", () => {
    plausibleSendEvent("Carousel previous", {
      props: { index: controller.currentSlide },
    });
    controller.prevSlide();
    if (!pauseRequested) {
      startTimer();
    }
  });
  nextButton.addEventListener("click", () => {
    plausibleSendEvent("Carousel next", {
      props: { index: controller.currentSlide },
    });
    controller.nextSlide();
    if (!pauseRequested) {
      startTimer();
    }
  });
  slider.addEventListener(
    "scroll",
    debounce(() => {
      const newSlide = Math.round(slider.scrollLeft / slider.offsetWidth);
      if (newSlide !== controller.currentSlide) {
        controller.updateSlider(newSlide);
        if (!pauseRequested) {
          startTimer();
        }
      }
    }, 100),
  );

  if (prefersReducedMotion()) {
    pauseLabel.remove();
    pauseInput.remove();
  } else {
    pauseInput.addEventListener("change", () => {
      if (!pauseRequested) {
        pauseRequested = true;
        stopTimer();
      } else {
        pauseRequested = false;
        startTimer();
      }
    });

    startTimer();
    if (pauseInput) {
      pauseInput.checked = false;
    }
  }
});
