import {
  api,
  cleanupUrlString,
  debounce,
  getClampedRandomInt,
  processDomElementOnce,
  Signal,
} from "../clientScript/clientDependencies.ts";
import { startGame } from "./clapsGame.client.ts";

type ClapButton = HTMLButtonElement & { label: Element };

const pathname = cleanupUrlString(
  new URL(globalThis.location.href).pathname,
);

export const createConfetti = () => {
  const randomRotationAngle = getClampedRandomInt(360) + "deg";

  const particlesContainer = document.createElement("span");
  particlesContainer.dataset.is = "confetti";
  particlesContainer.addEventListener(
    "animationend",
    () => particlesContainer.remove(),
  );
  particlesContainer.style.transform = `rotate(${randomRotationAngle})`;

  let children = getClampedRandomInt(10, 5);

  particlesContainer.classList.add(`has-${children + 1}`);

  while (children-- >= 0) {
    const particle = document.createElement("span");
    particle.style.setProperty("--angle", getClampedRandomInt(25) + "deg");
    particle.style.setProperty(
      "--destination",
      getClampedRandomInt(55, 5) + "px",
    );
    particlesContainer.appendChild(particle);
  }

  return particlesContainer;
};

const getClapsOrRandom = () =>
  api.claps.get(pathname).then((amount) => amount).catch((e) => {
    console.error(e);
    return 0;
  });

getClapsOrRandom().then(
  (initialAmount: number) => {
    const clapsOnPage = new Set<
      readonly [Element, Element, Element, Element]
    >();

    const initialFormattedAmount = formatNumber(initialAmount);
    const maxClapsBeforeGameStarts = 20;
    const claps = Signal(initialAmount);
    const clapped = Signal(0);

    clapped.on(
      (amount: number) => {
        if (amount > maxClapsBeforeGameStarts) {
          startGame();
        }
      },
    );

    const setClapButtonAmount = (amount: number, formattedAmount: string) =>
    (
      [numberContainer, total, abbreviated, bubble]: readonly [
        Element,
        Element,
        Element,
        Element,
      ],
    ): void => {
      if (amount < 10) {
        numberContainer.classList.add("smallAmount");
      } else {
        numberContainer.classList.remove("smallAmount");
      }
      total.textContent = `${amount}`;
      abbreviated.textContent = formattedAmount;
      bubble.textContent = clapped.get() > 0 ? `+${clapped.get()}` : "";
    };

    const setAmount = (amount: number): void => {
      const formattedAmount = formatNumber(amount);
      clapsOnPage.forEach(setClapButtonAmount(amount, formattedAmount));
    };

    function increase(this: ClapButton) {
      this.setAttribute("aria-pressed", "true");
      clapped.set(clapped.get() + 1);
      claps.set(claps.get() + 1);
      this.label.appendChild(createConfetti());
    }

    function formatNumber(number = 0) {
      return number.toLocaleString("en-US", {
        maximumFractionDigits: 2,
        notation: "compact",
        compactDisplay: "short",
      });
    }

    processDomElementOnce("button.clapsButton", (button: ClapButton) => {
      const numberContainer = button.querySelector(".clapsButtonAmount");
      if (!numberContainer) {
        return;
      }
      const total = numberContainer.querySelector(".clapsButtonAmountTotal");
      const abbreviated = numberContainer.querySelector(
        ".clapsButtonAmountAbbreviated",
      );
      const bubble = button.querySelector(".clapsButtonBubble");
      const label = button.querySelector(".clapsButtonLabel");

      if (!total || !abbreviated || !bubble || !label) {
        return;
      }

      abbreviated.removeAttribute("hidden");

      const cache = [numberContainer, total, abbreviated, bubble] as const;

      clapsOnPage.add(cache);
      setClapButtonAmount(initialAmount, initialFormattedAmount)(cache);

      button.addEventListener(
        "animationend",
        (event) => {
          if (event.animationName === "clapTotal") {
            button.setAttribute("aria-pressed", "false");
          }
        },
      );

      button.label = label;
      button.addEventListener("click", increase);
    });

    clapped.on(
      debounce(() => {
        api.claps.add(clapped.get(), pathname);
      }, 1000),
    );

    claps.on(setAmount);
  },
);
