import {
  h,
  processDomElementOnce,
} from "../clientScript/clientDependencies.ts";

const { button } = h;

export class ToggleShowEvent extends Event {
  public readonly isHidden: boolean;
  constructor(
    public readonly isShown: boolean,
    public readonly controls: HTMLElement,
    eventInitDict?: EventInit,
  ) {
    super("toggler-toggleshow", eventInitDict);
    this.controls = controls;
    this.isHidden = !isShown;
  }
}

declare global {
  interface GlobalEventHandlersEventMap {
    "toggler-toggleshow": ToggleShowEvent;
  }
}

function toggleButton(this: HTMLButtonElement) {
  const expanded = this.getAttribute("aria-expanded") === "true";
  this.setAttribute("aria-expanded", expanded ? "false" : "true");
  const targetElementID = this.getAttribute("aria-controls");
  const targetElement = targetElementID
    ? document.getElementById(targetElementID)
    : null;
  if (!targetElement) {
    return;
  }
  const targetToggledClassName = this.dataset["toggledClass"];
  if (targetToggledClassName) {
    if (expanded) {
      targetElement.classList.remove(targetToggledClassName);
    } else {
      targetElement.classList.add(targetToggledClassName);
    }
    const event = new ToggleShowEvent(!expanded, targetElement);
    this.dispatchEvent(event);
  }
  const bodyClassName = this.dataset["bodyClass"];
  if (bodyClassName) {
    if (expanded) {
      document.body.classList.remove(bodyClassName);
    } else {
      document.body.classList.add(bodyClassName);
    }
  }
}

export const processTogglerButton = (button: HTMLButtonElement) => {
  if (
    !button ||
    !(button.tagName === "BUTTON")
  ) {
    return;
  }
  if (!button.dataset["toggledClass"]) {
    button.dataset["toggledClass"] = "isToggled";
  }
  button.addEventListener("click", toggleButton);
  if (
    button.dataset["startExpanded"] != null &&
    (button.dataset["startExpanded"] !== button.getAttribute("aria-expanded"))
  ) {
    button.click();
  }
};

processDomElementOnce("button[data-is='toggler-button']", processTogglerButton);

export const TogglerButton = (
  props: { ariaControls: string } & Record<string, unknown>,
  ...children: Element[]
) => {
  const toggleButton = button(
    {
      ariaExpanded: "false",
      ariaLabel: "Toggle content",
      dataIs: "toggler-button",
      ...props,
    },
    ...children,
  );
  processTogglerButton(toggleButton);
  return toggleButton;
};
