import {
  DataBearingError,
  debounce,
  ensureAllElementsNotNull,
  FetcherSignal,
  h,
  pick,
  plausibleSendEvent,
  processDomElementOnce,
  querySelector,
  querySelectorAll,
  type SearchableItem,
  searchParamsToObj,
  Signal,
} from "../clientScript/clientDependencies.ts";
import {
  createLibrarySearchEngine,
  type SearchFilters,
  type SearchResult,
} from "../clientScript/searchEngine.ts";
import { createSuggestionsDropdown } from "../clientScript/mainSearchSuggestions.ts";

const { span, replace, a, em } = h;

const classPrefix = "mainSearch";

processDomElementOnce<HTMLDivElement>(
  `.${classPrefix}`,
  (searchWrapper) => {
    /**
     * Removes the loading overlay and enables pointer events on the search bar
     * We have to declare this here so it can be used everywhere else below
     */
    const enableUI = () => {
      const loadingOverlay = querySelector(`.${classPrefix}Loading`, {
        parent: searchWrapper,
      });
      loadingOverlay?.addEventListener(
        "transitionend",
        () => {
          loadingOverlay.remove();
        },
        { once: true },
      );
      searchWrapper.classList.add("loaded");
      searchWrapper.style.removeProperty("pointer-events");
    };

    /*********************************************************
     *
     * INTEGRITY CHECK
     *
     * We verify we have everything we need
     *
     ********************************************************/

    /**
     * Determines if this is a page with filters. If it isn't one, we're not on the search page.
     * In that case, we let the form behave normally and simply redirect to the search results page.
     */
    if (!("showFiltersButtons" in searchWrapper.dataset)) {
      enableUI();
      return;
    }

    /** URL to load the search index from. If not found, it's an error and we exit early */
    const dataURL = searchWrapper.dataset.searchUrl;
    if (!dataURL) {
      throw new DataBearingError(
        enableUI,
        "No data URL provided for search index",
      );
    }

    /**
     * All necessary elements for the search functionality.
     * If one of them is missing, we bail
     */
    const elements = (() => {
      const gridListId = searchWrapper.dataset.gridListId;
      const summaryId = searchWrapper.dataset.summaryId;
      // if there isn't anything to filter, we aren't on a search page. Exit early.
      if (!gridListId || !summaryId) {
        console.error(
          "No grid list or summary ID provided for search filtering",
        );
        return;
      }
      return ensureAllElementsNotNull(
        document.getElementById(gridListId),
        document.getElementById(summaryId),
        querySelector(`form`, { parent: searchWrapper }),
        querySelector<HTMLInputElement>(`input[type="search"]`, {
          parent: searchWrapper,
        }),
        querySelector<HTMLDivElement>(`#${classPrefix}Filters`, {
          parent: searchWrapper,
        }),
        querySelector<HTMLDivElement>(`.${classPrefix}SelectedTerms`, {
          parent: searchWrapper,
        }),
        querySelector<HTMLDivElement>(`.${classPrefix}Suggestions`, {
          parent: searchWrapper,
        }),
      );
    })();

    if (elements == null) {
      throw new DataBearingError(
        enableUI,
        "Some elements were not found in the DOM",
      );
    }

    const [
      /** List of item cards */
      gridList,
      /** Summary element that displays "X out of Y results" */
      summary,
      /** Search form */
      searchForm,
      /** Search input inside the search form */
      searchInput,
      /** Filters container, options, checkboxes */
      filtersContainer,
      /** Selected terms container, buttons to remove selected filters */
      selectedTermsContainer,
      /** Suggestions dropdown container */
      suggestionsContainer,
    ] = elements;

    searchForm.setAttribute("autocomplete", "off");
    searchInput.setAttribute("autocorrect", "off");
    searchInput.setAttribute("autocapitalize", "none");
    searchInput.setAttribute("spellcheck", "false");

    const cardsBeforeAugmentation = querySelectorAll<HTMLLIElement>(
      ".itemCard",
      {
        parent: gridList,
      },
    );
    if (cardsBeforeAugmentation == null) {
      throw new DataBearingError(
        enableUI,
        "Cards were were not found in the DOM",
      );
    }

    /*********************************************************
     *
     * FILTERS UI BOOTSTRAP
     *
     * We prepare all the filtering elements here.
     *
     ********************************************************/

    // in order to avoid showing all results before the search query is applied, first, hide
    // everything
    gridList.classList.add("isFiltered");

    /**
     * A map of all inputs used for filtering
     * Each filter is augmented with a `linkedLabel` property that points to the corresponding selected term button
     * Similarly, each selected term button has a `linkedInput` property that points to the corresponding input
     */
    const activeFiltersMap = (() => {
      const filtersElements = ensureAllElementsNotNull(
        querySelectorAll<HTMLInputElement | HTMLButtonElement>(
          "input, button.resetSection",
          {
            parent: filtersContainer,
          },
        ),
        querySelectorAll<ControlledLabel>(`label`, {
          parent: selectedTermsContainer,
        }),
        querySelector<HTMLButtonElement>(
          `.${classPrefix}SelectedTermsClearAllButton`,
          {
            parent: selectedTermsContainer,
          },
        ),
      );

      if (filtersElements == null) {
        throw new DataBearingError(
          enableUI,
          "Some filter elements were not found in the DOM",
        );
      }

      const [
        /** Array of input elements inside the filters container. These are the checkboxes and options */
        allFilterElements,
        /** Array of label elements inside the selected terms container. These are the selected term buttons */
        allSelectedTermLabels,
        /** "Clear all" button that removes all selected filters */
        clearAllButton,
      ] = filtersElements;

      type ControlledInput = HTMLInputElement & {
        linkedLabel: HTMLLabelElement;
      };

      type ControlledLabel = HTMLLabelElement & {
        linkedInput: HTMLInputElement;
      };

      const activeFiltersMap = Signal(new Map<string, Set<string>>());

      const createFilterCategory = () => {
        const selected = Signal(new Set<HTMLInputElement>());
        const values = Signal(new Set<string>());

        selected.on((newSelected) => {
          const newValues = new Set<string>();
          newSelected.forEach((input) => {
            input.value.split(" ").forEach((val) => newValues.add(val));
          });
          values.set(newValues);
        });

        return {
          type: null as "radio" | "checkbox" | null,
          mainInput: null as HTMLInputElement | null,
          resetButton: null as HTMLButtonElement | null,
          collection: new Set<ControlledInput>(),
          selected,
          values,
        };
      };

      type FilterCategory = ReturnType<typeof createFilterCategory>;
      type ProcessedFilterCategory =
        & Omit<
          FilterCategory,
          "type" | "mainInput"
        >
        & {
          type: "radio" | "checkbox";
          mainInput: HTMLInputElement;
        };

      const filters = new Map<string, FilterCategory>();
      const filtersById = new Map<string, ControlledInput>();

      allFilterElements.forEach((inputOrButton) => {
        const categoryName = inputOrButton.getAttribute("name") || "";
        // create the category if it doesn't exist,
        // with associated values signal
        if (!filters.has(categoryName)) {
          activeFiltersMap.get().set(categoryName, new Set());
          const category = createFilterCategory();
          filters.set(categoryName, category);
          category.values.on((newValues) => {
            const currentValues = activeFiltersMap.get();
            currentValues.set(categoryName, newValues);
            activeFiltersMap.set(currentValues, true);
          });
        }
        const category = filters.get(categoryName)!;
        if (inputOrButton.tagName === "BUTTON") {
          const button = inputOrButton as HTMLButtonElement;
          category.resetButton = button;
        } else {
          const input = inputOrButton as HTMLInputElement;
          if (input.classList.contains("resetSection")) {
            category.mainInput = input;
          } else {
            const controlledInput = input as ControlledInput;
            category.collection.add(controlledInput);
            if (category.type === null) {
              category.type = input.type === "radio" ? "radio" : "checkbox";
            }
            filtersById.set(input.id, controlledInput);
          }
        }
      });

      allSelectedTermLabels.forEach((label) => {
        const htmlFor = label.getAttribute("for");
        if (!htmlFor) {
          console.error("No 'for' attribute on selected term label", label);
          return;
        }
        const input = filtersById.get(htmlFor);
        if (!input) {
          console.error(
            `No input found with id ${htmlFor} for selected term label`,
            label,
          );
          return;
        }
        input.linkedLabel = label;
        label.linkedInput = input;
      });

      // sanity check
      // TODO: remove in production (as well as other similar checks)
      filters.forEach((category, categoryName) => {
        if (category.type === null || category.mainInput === null) {
          console.error(category);
          throw new DataBearingError(
            enableUI,
            `Incomplete filter category for ${categoryName}`,
          );
        }
      });

      const processedFilters = filters as Map<string, ProcessedFilterCategory>;

      /**
       * Meat and potatoes
       *
       * Here we link clicking on a selected term button with the logic.
       *
       * Clicking a term -> Signal is updated -> Signal decides which inputs to check/uncheck
       * Clicking a selectedTerm -> same
       *
       * If the term is part of a checkbox category, we simply toggle it.
       * If the term is part of a radio category, we uncheck all others and check this one.
       *
       * Logic:
       *
       * 1. When pressing a selected Filter Button, it unchecks the corresponding input
       * 2. When pressing a "clear all" button, it unchecks all corresponding inputs
       * 3. When checking/unchecking checkboxes, it updates the "All" radio button accordingly
       * 4. When pressing the "all" radio button, it unchecks all corresponding checkboxes
       * 5. When an input is selected, the corresponding selected term button is shown
       */

      processedFilters.forEach((category, _categoryName) => {
        const resetCategoryAndCancelEvent = (event: Event) => {
          event.preventDefault();
          category.selected.set(new Set());
        };

        // add or remove elements from the selected list when inputs change
        category.collection.forEach((input) => {
          // make sure to reset state after a page refresh
          input.checked = false;
          category.mainInput.checked = true;

          input.addEventListener("change", () => {
            const selected = category.selected.get();
            if (input.type === "radio") {
              selected.clear();
            }
            if (input.checked) {
              selected.add(input);
            } else {
              selected.delete(input);
            }
            category.selected.set(selected, true);
          });

          // react to selected term button clicks
          // for checkboxes, we can rely on the `change` event above
          // but for radios, we need to handle clicks separately
          if (category.type === "radio") {
            input.linkedLabel.addEventListener(
              "click",
              resetCategoryAndCancelEvent,
            );
          }
        });

        // reset buttons clicked
        category.mainInput.addEventListener(
          "change",
          resetCategoryAndCancelEvent,
        );
        category.resetButton?.addEventListener(
          "click",
          resetCategoryAndCancelEvent,
        );

        // react to selection changes
        category.selected.on((newSelected) => {
          category.mainInput.checked = newSelected.size === 0;
          category.collection.forEach((input) => {
            const shouldBeChecked = newSelected.has(input);
            input.checked = shouldBeChecked;
            input.linkedLabel.hidden = !shouldBeChecked;
          });
        });
      });

      const resetAll = () => {
        processedFilters.forEach((category) => {
          category.selected.set(new Set());
        });
      };

      clearAllButton.hidden = true;
      clearAllButton.addEventListener("click", resetAll);

      activeFiltersMap.on((newMap) => {
        let anyValueSelected = false;
        for (const [, values] of newMap) {
          if (values.size > 0) {
            anyValueSelected = true;
            break;
          }
        }
        clearAllButton.hidden = !anyValueSelected;
      });

      return { ...activeFiltersMap, resetAll };
    })();

    const getFiltersObject = (): SearchFilters =>
      Object.fromEntries(activeFiltersMap.get().entries());

    /*********************************************************
     *
     * Cards Augmentation
     *
     * In order to easily mark cards as search results or not,
     * we augment them with helper methods.
     * This is frowned upon in some circles, but no one will
     * know if we don't tell them.
     *
     ********************************************************/

    /**
     * We augment all cards, JQuery-style, with new methods
     */
    const { cards, clearCards } = (() => {
      const cardAugmentations = {
        isSearchResult(this: HTMLElement, score: number) {
          this.classList.add("isSearchResult");
          this.style.setProperty("--search-score", `${score}`);
        },
        isNotSearchResult(this: HTMLElement) {
          this.classList.remove("isSearchResult");
          this.style.removeProperty("--search-score");
        },
      };

      /**
       * Appends the `isSearchResult` and `isNotSearchResult` methods to the card element
       */
      const augmentCard = (
        card: HTMLLIElement,
      ): HTMLLIElement & typeof cardAugmentations =>
        Object.assign(card, cardAugmentations) as
          & HTMLLIElement
          & typeof cardAugmentations;

      /**
       * Map of all cards, keyed by their slug
       */
      const cards = new Map(
        cardsBeforeAugmentation.map((item) => [
          item.id.slice("card-for-".length),
          augmentCard(item),
        ]),
      );

      /**
       * Removes all search results styling from all cards
       */
      const clearCards = () =>
        cards.forEach((card) => card.isNotSearchResult());

      return { cards, clearCards };
    })();

    /*********************************************************
     *
     * Preparing Signals
     *
     * Signals are reactive data structures that update automatically
     * We have:
     * 1. A signal for the filters state, which updates when any filter input is changed
     * 2. A signal for the search results, which updates when the search is performed
     * 3. A signal for the amount of search results, which updates when the search results signal updates
     * 4. A signal for loading the search data from the JSON file
     *
     ********************************************************/

    /**
     * Records the amount of successful search results and total results
     */
    const searchResultsAmountState = Signal<[number, number]>([0, 0]);

    /**
     * Signal that loads the search data from the JSON file
     */
    const searchLoadedDataState = FetcherSignal<SearchIndexData>();

    /*********************************************************
     *
     * Preparing the Search Functionality
     *
     * Here we:
     *
     * 1. Prepare the live search function that runs anytime a filter is changed
     * 2. Prepare the reactive signals that fire anytime a filter is changed
     * 3. Prepare the client-side search function that runs when the form is submitted
     *
     * They will all then be tied together at the bottom of this file
     *
     ********************************************************/

    /**
     * Main search function.
     * Called when the search form is submitted
     * or when the filters are changed
     * When the text input is changed, filters are cleared.
     */
    const onSearchResultsChanged = (results: SearchResult[]) => {
      clearCards();

      let shown = 0;

      for (let i = 0; i < results.length; i++) {
        const { item, score } = results[i];
        const card = cards.get(item.slug);
        if (!card) {
          console.error(`Element not found for slug: ${item.slug}`);
          continue;
        }
        card.isSearchResult(score);
        card.style.order = String(i);
        shown += 1;
      }

      searchResultsAmountState.set([shown, searchResultsAmountState.get()[1]]);
    };

    /**
     * Updates the summary element that shows the amount of results found
     */
    const onSearchAmountChanged = ([amountOfValidResults, total]: [
      number,
      number,
    ]) => {
      const noResultsClass = "noResult";
      if (total === 0) {
        document.body.classList.remove(noResultsClass);
        replace(summary, span(""));
      } else if (amountOfValidResults === 0) {
        document.body.classList.add(noResultsClass);
        const hasAppliedFilters = activeFiltersMap.get().size > 0;
        const searchString = searchInput.value.trim();
        if (!hasAppliedFilters && searchString === "") {
          replace(summary, span("All results"));
          return;
        }
        const keywords: string[] = [];
        activeFiltersMap
          .get()
          .forEach((values) => values.forEach((value) => keywords.push(value)));
        if (searchString !== "") {
          keywords.push(searchString);
        }
        replace(
          summary,
          span(
            em("No results yet! "),
            a(
              {
                href: `https://school.gdquest.com/about-us/contact?subject=${
                  encodeURIComponent(
                    "Suggest an article",
                  )
                }`,
              },
              "Suggest a subject",
            ),
          ),
        );
      } else {
        document.body.classList.remove(noResultsClass);
        replace(
          summary,
          span({ className: "keyword" }, amountOfValidResults),
          span(` result${amountOfValidResults === 1 ? "" : "s"} out of `),
          a(
            { href: "/library/search#CardSearch", className: "keyword" },
            total,
          ),
        );
      }
    };

    /**
     * Called after the search data is loaded from the json file.
     * Takes care of setting events handlers on the form
     * @param data Data loaded from the search index JSON file
     */
    const onSearchDataLoaded = (data: SearchIndexData) => {
      const { items } = data;
      const total = items.length;
      searchResultsAmountState.set([total, total]);
      const engine = createLibrarySearchEngine(items);

      const runSearch = (
        query: string,
        filters: SearchFilters,
      ): SearchResult[] => engine.search(query, { filters });

      const currentQueryState = Signal("");

      let updateResultsPending = false;
      const scheduleUpdateResults = () => {
        if (!updateResultsPending) {
          updateResultsPending = true;
          queueMicrotask(() => {
            updateResultsPending = false;
            updateResults();
          });
        }
      };

      const updateResults = () => {
        const query = currentQueryState.get();
        const filters = getFiltersObject();
        const hasQuery = query.length > 0;
        const hasFilters = Object.values(filters).some((s) => s.size > 0);

        plausibleSendEvent("Main Search", {
          props: Object.keys(filters).reduce(
            (acc: Record<string, string>, key) => {
              if (filters[key].size > 0) {
                acc[key] = Array.from(filters[key]).join(", ");
              }
              return acc;
            },
            query ? { query } : {},
          ),
        });

        if (!hasQuery && !hasFilters) {
          gridList.classList.remove("isFiltered");
          clearCards();
          searchResultsAmountState.set([total, total]);
          return;
        }

        gridList.classList.add("isFiltered");
        const results = runSearch(query, filters);
        onSearchResultsChanged(results);
      };

      const setQuery = (
        searchPattern?: string | null,
        { updateHistory = true } = {},
      ) => {
        const query = typeof searchPattern === "string"
          ? searchPattern.trim()
          : "";

        currentQueryState.set(query);
        searchInput.value = query;

        if (updateHistory) {
          if (query === "") {
            globalThis.history.replaceState(
              null,
              "",
              globalThis.location.pathname,
            );
          }
        }
        suggestions?.clear();
        scheduleUpdateResults();
      };

      const suggestions = suggestionsContainer
        ? createSuggestionsDropdown({
          classPrefix,
          container: suggestionsContainer,
          input: searchInput,
          onSelect: (value: string) => {
            activeFiltersMap.resetAll();
            setQuery(value);
          },
        })
        : null;

      const updateSuggestions = suggestions
        ? debounce(() => {
          const query = searchInput.value.trim();
          if (query.length < 2) {
            suggestions.clear();
            return;
          }
          const nextSuggestions = engine.suggest(query);
          suggestions.render(nextSuggestions);
        }, 120)
        : null;

      if (suggestions && updateSuggestions) {
        searchInput.addEventListener("input", () => {
          updateSuggestions();
        });
        searchInput.addEventListener("keydown", (event) => {
          if (suggestions.handleKey(event)) {
            event.preventDefault();
          }
        });
      }

      searchForm.addEventListener("submit", (e) => {
        e.preventDefault();
        const query = new FormData(searchForm).get("search");
        if (typeof query !== "string") {
          return;
        }
        activeFiltersMap.resetAll();
        globalThis.history.replaceState(
          null,
          "",
          `?search=${encodeURIComponent(query)}`,
        );
        setQuery(query, { updateHistory: false });
      });

      const { search: searchQuery = false } = pick(
        searchParamsToObj(globalThis.location.search, {
          single: true,
          joinArrayChar: false,
        }),
        ["search"],
      );

      if (searchQuery !== false && searchQuery.length > 0) {
        setQuery(searchQuery, { updateHistory: false });
      } else {
        // update even when there is no search, so that we can show all results
        updateResults();
      }

      activeFiltersMap.on(scheduleUpdateResults);
    };

    type SearchIndexData = {
      items: SearchableItem[];
      metadata: {
        version: number;
        generatedAt: string;
      };
    };

    searchLoadedDataState.on(({ status, data }) => {
      if (status === "success") {
        onSearchDataLoaded(data);
        enableUI();
      } else if (status === "error") {
        console.error("Failed to load search data with status", {
          status,
          data,
          dataURL,
        });
      }
    });

    searchResultsAmountState.on(onSearchAmountChanged);

    searchLoadedDataState.load(dataURL);
  },
  {
    onError: (error) => {
      if (
        error instanceof DataBearingError &&
        typeof error.data === "function"
      ) {
        const restoreUI = error.data;
        console.error("Error setting up main search component:", error.message);
        restoreUI();
      } else {
        throw error;
      }
    },
  },
);
