/**
 * Cleans up a URL string by removing leading and trailing slashes and replacing multiple consecutive slashes with a single slash.
 *
 * @param path - The URL string to be cleaned up.
 * @returns The cleaned up URL string.
 */
export const cleanupUrlString = (path: string) =>
  path.replace(/^\/|\/$/g, "").replace(/\/+/g, "/");
