interface SearchParamsToObjOptsBase {
  /**
   * Only used if `single` is `true`. Joins arrays with this character;
   * Set to `false` to return the first value instead of joining.
   * Defaults to space `" "`.
   */
  joinArrayChar?: false | string;
}

interface SearchParamsToObjOptsSingle extends SearchParamsToObjOptsBase {
  /**
   * If true, the function will return an object with all values as strings.
   * If false, the function will return an object with all values as arrays of strings.
   * @default false
   */
  single: true;
}

interface SearchParamsToObjOptsArray extends SearchParamsToObjOptsBase {
  /**
   * If true, the function will return an object with all values as strings.
   * If false, the function will return an object with all values as arrays of strings.
   * @default false
   */
  single?: false | undefined;
}

type SearchParamsToObjOpts =
  | SearchParamsToObjOptsSingle
  | SearchParamsToObjOptsArray;

/**
 * Converts a URLSearchParams object or a query string into a plain object.
 * @param search The URLSearchParams object or query string to convert.
 * @param opts Options for controlling the conversion behavior.
 * @returns A plain object representation of the search parameters.
 */
export function searchParamsToObj(
  search: string | URLSearchParams,
  opts: SearchParamsToObjOptsSingle,
): Record<string, string>;
export function searchParamsToObj(
  search: string | URLSearchParams,
  opts?: SearchParamsToObjOptsArray,
): Record<string, string[]>;
export function searchParamsToObj(
  search: string | URLSearchParams,
  { single = false, joinArrayChar = " " }: SearchParamsToObjOpts = {},
): Record<string, string> | Record<string, string[]> {
  search = search instanceof URLSearchParams
    ? search
    : new URLSearchParams(search);
  const result: Record<string, string[]> = {};
  search.forEach((value, key) => {
    result[key] = result[key] || [];
    result[key].push(value);
  });
  if (single) {
    const singleResult: Record<string, string> = {};
    for (const key in result) {
      singleResult[key] = joinArrayChar
        ? result[key].join(joinArrayChar)
        : result[key][0];
    }
    return singleResult;
  }
  return result;
}
