import { MapSignal } from "../any/MapSignal.ts";
import { LocalStorageSignalAdapter } from "./LocalStorageSignalAdapter.ts";

export const TYPE_SUCCESS = "success";
export const TYPE_ERROR = "error";
export const TYPE_INFO = "info";
export const TYPE_WARNING = "warning";

export type UserMessageType =
  | typeof TYPE_SUCCESS
  | typeof TYPE_ERROR
  | typeof TYPE_INFO
  | typeof TYPE_WARNING;

type MessageRepository = Record<
  string,
  { message: string; type: UserMessageType }
>;

interface UserMessagesCollection {
  add: (
    type: UserMessageType,
    message: string,
    id?: string,
  ) => string;
  addSuccess: (message: string) => string;
  addError: (message: string) => string;
  addInfo: (message: string) => string;
  addWarning: (message: string) => string;
  remove: (id: string) => void;
  get: (id: string) => { message: string; type: UserMessageType } | undefined;
  entries: () => [string, { message: string; type: UserMessageType }][];

  onMessageAdded: (
    fn: (
      key: string,
      value: { message: string; type: UserMessageType },
    ) => void,
  ) => void;
  onMessageRemoved: (
    fn: (
      key: string,
      value?: { message: string; type: UserMessageType },
    ) => void,
  ) => void;
  offMessageAdded: (
    fn: (
      key: string,
      value: { message: string; type: UserMessageType },
    ) => void,
  ) => void;
  offMessageRemoved: (
    fn: (
      key: string,
      value?: { message: string; type: UserMessageType },
    ) => void,
  ) => void;
}

/**
 * A collection of messages that are displayed to the user.
 * Each message gets recorded to localstorage, so it continues to show between refreshes.
 * This library doesn't handle the display of the messages, only the storage and retrieval.
 */
const makeUserMessagesCollection = (): UserMessagesCollection => {
  const signal = LocalStorageSignalAdapter(
    MapSignal({} as MessageRepository),
    "__userMessages",
  );

  const add = (type: UserMessageType, message: string, id?: string) => {
    id = id ||
      `usermessage-` + type + "-" + Math.random().toString(36).slice(2);
    signal.setItem(id, { message, type });
    return id;
  };

  const addSuccess = (message: string) => add(TYPE_SUCCESS, message);
  const addError = (message: string) => add(TYPE_ERROR, message);
  const addInfo = (message: string) => add(TYPE_INFO, message);
  const addWarning = (message: string) => add(TYPE_WARNING, message);

  const remove = (id: string) => signal.removeItem(id);

  const get = (id: string) => signal.getItem(id);
  const entries = () => Object.entries(signal.get());

  return {
    add,
    addSuccess,
    addError,
    addInfo,
    addWarning,
    remove,
    get,
    entries,
    onMessageAdded: signal.onKeyAdded,
    onMessageRemoved: signal.onKeyRemoved,
    offMessageAdded: signal.offKeyAdded,
    offMessageRemoved: signal.offKeyRemoved,
  };
};

let _cache: UserMessagesCollection | null = null;

export const userMessagesCollection = (): UserMessagesCollection => {
  if (!_cache) {
    _cache = makeUserMessagesCollection();
  }
  return _cache;
};
