import { toURLParams } from "../any/toURLParams.ts";
import { disableForm, enableForm } from "./enableOrDisableForm.ts";
import {
  handleSimpleFormSubmit,
  type SimpleSerializedForm,
} from "./handleSimpleFormSubmit.ts";
import type { HttpMethod } from "../types/HttpMethod.ts";

type AllowedMethodTypes = HttpMethod | "JSON" | "AUTO";

const pickCorrectFetch = (
  type: AllowedMethodTypes,
  serialized: SimpleSerializedForm,
) => {
  if (type === "AUTO") {
    type = serialized.method || "GET";
  }
  switch (type) {
    case "JSON": {
      const json = JSON.stringify(serialized.values);
      return fetch(serialized.action, {
        method: serialized.method,
        body: json,
        headers: {
          "Content-Type": "application/json",
          "Accept": "application/json",
        },
      });
    }
    case "GET": {
      const params = serialized.values ? toURLParams(serialized.values) : "";
      const url = `${serialized.action}${params ? "?" + params : ""}`;
      return fetch(url, {
        method: serialized.method,
        headers: {
          "Accept": "application/json",
        },
      });
    }
  }
  const enctype =
    (serialized.enctype && serialized.enctype === "multipart/form-data")
      ? "multipart/form-data"
      : "application/x-www-form-urlencoded";
  const body = serialized.values
    ? enctype === "multipart/form-data"
      ? serialized.values
      : toURLParams(serialized.values)
    : "";
  return fetch(serialized.action, {
    method: serialized.method,
    body,
    headers: {
      "Content-Type": enctype,
      "Accept": "application/json",
    },
  });
};

interface EnhanceFormConfig {
  method: AllowedMethodTypes;
  classBusy: string | false;
  doDisableForm: boolean;
  doReEnableForm: boolean | number;
  callback?: (error: Error | null, response: Response | null) => void;
}

const defaultConfig: EnhanceFormConfig = {
  method: "AUTO" as const,
  classBusy: "busy",
  doDisableForm: true,
  doReEnableForm: true,
};

/**
 * Automatically fetches the form data when the form is submitted.
 * Optionally disables the form and adds a class to it while fetching.
 *
 * Reads the entire configuration for fetching from the form itself.
 *
 * Can take an old-school nodeback function, with the error as the first argument.
 * @param callback
 * @param config
 */
export const autoFetchWhenSubmit = (
  config: Partial<EnhanceFormConfig> = defaultConfig,
): (event: SubmitEvent | Event) => void => {
  const { method, classBusy, doDisableForm, doReEnableForm, callback } = {
    ...defaultConfig,
    ...config,
  };
  const useSerializedData = (
    serialized: SimpleSerializedForm,
    form: HTMLFormElement,
  ) => {
    const promise = pickCorrectFetch(method, serialized);

    doDisableForm && disableForm(form);
    classBusy && form.classList.add(classBusy);

    if (callback != null) {
      promise
        .then((response) => callback(null, response))
        .catch((error) => callback(error, null));
    }
    promise.finally(() => {
      if (doReEnableForm === true) {
        enableForm(form);
      } else if (typeof doReEnableForm === "number") {
        setTimeout(() => enableForm(form), doReEnableForm);
      }
      classBusy && form.classList.remove(classBusy);
    });
    return promise;
  };
  return handleSimpleFormSubmit(useSerializedData);
};
