import type { HttpMethod } from "../types/mod.ts";
import type { SerializedForm } from "./serializeComplicatedForm.ts";

export type SimpleSerializedForm = Omit<SerializedForm, "values" | "method"> & {
  values: FormData;
  method: HttpMethod | "";
};

type FormHandler = (
  serialized: SimpleSerializedForm,
  form: HTMLFormElement,
) => void;

/**
 * A wrapper that simplifies form submission handling.
 * It prevents default form submission behavior, stops event propagation,
 * and serializes the form data into a simplified format, ready to be used in
 * various contexts such as API requests or client-side validation.
 * **note**: this serialization method uses `FormData` to serialize form data; for complex forms with
 * repeating fields, conditions, or nested structures, consider using the more expensive method
 * [serializeComplicatedForm]({@link ./serializeComplicatedForm.ts})
 */
export const handleSimpleFormSubmit =
  (callback: FormHandler) => (event: SubmitEvent | Event) => {
    event.preventDefault();
    event.stopPropagation();
    const form = event.target as HTMLFormElement;
    const action = form.getAttribute("action") || "";
    const formName = form.getAttribute("name") || "";
    const enctype = form.getAttribute("enctype") || "";
    const method = (form.getAttribute("method") || "")
      .toUpperCase() as (HttpMethod | "");
    const target = form.getAttribute("target") || "";
    const values = new FormData(form);

    const serialized: SimpleSerializedForm = {
      name: formName,
      action,
      method,
      values,
      enctype,
      target,
    };

    callback(serialized, form);
  };
