import {
  type AdvancedMechanicsNodeInput,
  FetcherSignal,
  getClampedRandomInt,
  h,
  processDomElementOnce,
  shuffleArray,
} from "../clientScript/clientDependencies.ts";
import { NodeFlashCard } from "./NodeFlashCard.client.ts";

const { replace } = h;

const nodeEssentialsData = FetcherSignal<{
  list: AdvancedMechanicsNodeInput[];
}>();

processDomElementOnce<HTMLElement>(".nodeFlashCardShuffler", (element) => {
  const contentPane = element.querySelector<HTMLElement>(
    ".nodeFlashCardShufflerContentPane",
  );
  const buttons = element.querySelectorAll<HTMLElement>(
    "button.nodeFlashCardShufflerButton",
  );
  const grid = element.querySelector<HTMLElement>(".nodeFlashCardShufflerGrid");

  if (!contentPane || !grid) {
    console.error("Missing required elements for Node Flashcard Shuffler");
    return;
  }

  const dataURL = element.dataset.nodesUrl;
  if (!dataURL) {
    console.error("No data URL found for Node Flashcard Shuffler");
    return;
  }

  const setStateLoading = (loading: boolean) => {
    contentPane.setAttribute("aria-busy", loading ? "true" : "false");
    buttons.forEach((button) =>
      loading
        ? button.setAttribute("disabled", "")
        : button.removeAttribute("disabled")
    );
  };

  grid.addEventListener("animationend", () => grid.classList.remove("slideIn"));

  const data: AdvancedMechanicsNodeInput[] = [];
  let currentIndex = 0;

  const pickThreeNextCards = () => {
    if (data.length === 0) {
      return;
    }
    setStateLoading(false);
    const nextIndex = currentIndex + 3;
    if (nextIndex >= data.length) {
      currentIndex = 0; // reset index to loop through the data again
      assignNodeData();
    }
    const nextCards = data.slice(currentIndex, nextIndex);
    currentIndex = nextIndex;
    replace(grid, ...nextCards.map(NodeFlashCard));
    grid.classList.add("slideIn");
  };

  const fakeLoadAndPickThree = () => {
    setStateLoading(true);
    setTimeout(pickThreeNextCards, getClampedRandomInt(300, 1000));
  };

  const onClick = (_event: MouseEvent) => {
    if (contentPane.getAttribute("aria-busy") === "true") {
      return;
    }
    fakeLoadAndPickThree();
  };

  const assignNodeData = () => {
    const incomingData = nodeEssentialsData.data();
    if (!incomingData) {
      return;
    }
    data.length = 0; // clear previous data
    data.push(...shuffleArray(incomingData.list));
    // duplicate items at the end if the length is not a multiple of 3
    const remainder = data.length % 3;
    if (remainder !== 0) {
      const itemsToAdd = 3 - remainder;
      const lastItems = data.slice(-itemsToAdd);
      data.push(...lastItems);
    }
  };

  nodeEssentialsData.on(({ status }) => {
    if (status !== "success") {
      setStateLoading(true);
    } else {
      assignNodeData();
      pickThreeNextCards();
      setStateLoading(false);
    }
  });

  buttons.forEach((button) => button.addEventListener("click", onClick));

  setStateLoading(true);
  nodeEssentialsData.load(dataURL);
});
