const _classCache = new Set<string>();
import { ABORT } from "../any/symbols.ts";

interface ProcessDomElementOnceOptions {
  /**
   * the class name to add to each processed element. Defaults to a generated class name if none was provided.
   */
  className?: string;
  /**
   * the root element to query from. Defaults to `document`.
   */
  root?: HTMLElement;
  /**
   * If provided, this function is called when an error occurs during processing.
   * Otherwise, errors are re-thrown.
   * When handling an error,
   * @param error the error that occurred during processing.
   * @param ABORT - the ABORT symbol. If returned from the onError function, processing is aborted for all further elements.
   */
  onError?: (error: unknown, ABORT: ABORT) => ABORT | void;
}

/**
 * Safe function to attach behaviors to DOM elements, when you want to ensure the behavior is only applied once.
 * each element is ensured to be processed once through applying a gating class name.
 * Additionally to that specific class name, the class `isJSProcessed` is added to each processed element, which can be used to style elements in CSS.
 * @param selectors - The CSS selector for the elements to process.
 * @param functor - The function to apply to each element.
 * @param opts - Options
 */
export function processDomElementOnce<
  K extends keyof HTMLElementTagNameMap,
  E extends NodeListOf<HTMLElementTagNameMap[K]>
>(
  selectors: K,
  functor: (element: E) => void,
  opts?: ProcessDomElementOnceOptions
): void;
export function processDomElementOnce<
  K extends keyof SVGElementTagNameMap,
  E extends NodeListOf<SVGElementTagNameMap[K]>
>(
  selectors: K,
  functor: (element: E) => void,
  opts?: ProcessDomElementOnceOptions
): void;
export function processDomElementOnce<
  K extends keyof MathMLElementTagNameMap,
  E extends NodeListOf<MathMLElementTagNameMap[K]>
>(
  selectors: K,
  functor: (element: E) => void,
  opts?: ProcessDomElementOnceOptions
): void;
export function processDomElementOnce<E extends HTMLElement>(
  selectors: string,
  functor: (element: E) => void,
  opts?: ProcessDomElementOnceOptions
): void;
export function processDomElementOnce<E extends HTMLElement>(
  selectors: string,
  functor: (element: E) => void,
  opts?: ProcessDomElementOnceOptions
) {
  const { className, root = document, onError } = opts || {};
  let addedClass =
    className ||
    `js-processed-${
      functor.name ? functor.name : selectors.replaceAll(/[^a-zA-Z0-9]/g, "-")
    }`;

  let n = 1;
  while (_classCache.has(addedClass) && n < 1000) {
    // arbitrary limit to prevent infinite loop
    addedClass = addedClass + n++;
  }

  _classCache.add(addedClass);

  const elements = root.querySelectorAll<E>(selectors);
  if (!elements || !elements.length) {
    //console.warn(`didn't find any element for selector "${selectors}"`);
    return;
  }
  elements.forEach((element) => {
    if (!element.classList.contains(addedClass)) {
      element.classList.add("isJSProcessed", addedClass);
      if (onError) {
        try {
          functor(element);
        } catch (error) {
          const result = onError(error, ABORT);
          if (result === ABORT) {
            return;
          }
        }
      } else {
        functor(element);
      }
    }
  });
}
