interface ControlSpec {
  name: string;
  min?: number;
  max?: number;
}

interface ShaderUniformHint {
  min: number;
  max: number;
  step: number;
}

type ShaderUniformDefault = { type: string; value: number[] };
type ShaderUniformHints = Record<string, ShaderUniformHint>;
export type ShaderUniformDefaults = Record<string, ShaderUniformDefault>;

// Scans a gdshader source for float/vec* uniform declarations and extracts
// their default values. Returns `{ name: { type, value: number[] } }`.

/**
 * Scans a gdshader source for float/vec* uniform declarations and extracts
 * their default values. Returns `{ name: { type, value: number[] } }`.
 * @param source 
 * @returns 
 */
function parseUniformDefaults(source: string): ShaderUniformDefaults {
  const result: ShaderUniformDefaults = {};
  const pattern =
    /uniform\s+(float|vec[234])\s+(\w+)\s*(?::[^=;\n]+)?(?:=\s*([^;\n]+))?;/g;
  let match;
  while ((match = pattern.exec(source)) !== null) {
    const type = match[1];
    const name = match[2];
    const defaultStr = match[3]?.trim();
    let value: number[];
    if (defaultStr) {
      if (type === "float") {
        const parsed = Number.parseFloat(defaultStr)
        if (isNaN(parsed)) {
          throw new Error(
            `Could not parse default value for uniform '${name}': expected a float, got '${defaultStr}`
          )
        }
        value = [parsed];
      } else {
        const inner = defaultStr.match(/\(([^)]+)\)/)?.[1];
        if (!inner) {
          throw new Error(
            `Malformed default value for uniform '${name}': expected ${type}(...) constructor syntax, got '${defaultStr}'`
          )
        }
        value = inner.split(",").map((s) => {
          const parsed = parseFloat(s.trim());
          if (isNaN(parsed)) throw new Error(
            `parseUniformDefaults: could not parse component '${s.trim()}' in default value for uniform '${name}'.`
          );
          return parsed;
        });
      }
    } else {
      const componentCount = type === "float" ? 1 : parseInt(type[3], 10);
      value = Array.from({ length: componentCount }, () => 0);
    }
    result[name] = { type, value };
  }
  return result;
}

function parseUniformHints(source: string): ShaderUniformHints {
  if (!source.trim()) {
    throw new Error("Shader source is empty");
  }

  const result: ShaderUniformHints = {};
  const pattern =
    /uniform\s+(?:float|vec[234])\s+(\w+)\s*:[^=;\n]*hint_range\s*\(\s*([^)]+)\)/g;
  let match;
  while ((match = pattern.exec(source)) !== null) {
    const name = match[1];
    const parts = match[2].split(",").map((s, i) => {
      const parsed = parseFloat(s.trim());
      if (isNaN(parsed)) {
        throw new Error(
          `Failed to parse hint_range argument ${i} for uniform '${name}'. Got '${s.trim()}'.`
        )
      }
      return parsed;
    });
    result[name] = {
      min: parts[0] ?? 0,
      max: parts[1] ?? 1,
      step: parts[2] ?? 0.01,
    };
  }
  return result;
}

function parseControlSpecs(controls: string): ControlSpec[] {
  if (!controls.trim()) {
    throw new Error("parseControlSpecs: controls string is empty.");
  }

  return controls.split(/,(?![^(]*\))/).flatMap((token) => {
    const trimmed = token.trim();
    if (!trimmed) return [];

    const match = trimmed.match(
      /^(\w+)\s*\(\s*([^,)]+)\s*,\s*([^)]+)\s*\)$/,
    );
    if (match) {
      const min = parseFloat(match[2])
      const max = parseFloat(match[3])

      if (isNaN(min)) {
        throw new Error(
          `Failed to parse min value for control '${match[1]}'. Got '${match[2]}'.`
        );
      }
      if (isNaN(max)) {
        throw new Error(
          `Failed to parse max value for control '${match[1]}'. Got '${match[3]}'.`
        );
      }
      if (min >= max) {
        throw new Error(
          `Control '${match[1]}' has min (${min}) >= max (${max}).`
        );
      }

      return [{ name: match[1], min, max }];
    }

    if (!/^\w+$/.test(trimmed)) {
      throw new Error(
        `'${trimmed}' is not a valid control name or range spec. Expected either 'uniform_name' or 'uniform_name(min, max)'.`
      );
    }

    const name = trimmed;
    return name ? [{ name }] : [];
  });
}

export const shaderControlUtils = {
  parseUniformDefaults,
  parseUniformHints,
  parseControlSpecs
}