/**
 * This module groups the logic to index and search the content of the library.
 *
 * Items are loaded and normalized at build time, then each query is evaluated
 * with rules that prioritize whole-phrase matches before falling back to
 * word-by-word scores and fuzzy matching (to still find relevant results even
 * with typos).
 */
import type { SearchableItem } from "../../toolbox/content/item/03_resolved.ts";

/**
 * This structure gives the base weight of different queries that play a role in
 * which entries are surfaced in the search results.
 */
const SCORE = {
  // These match the full user query phrase: When the complete search query
  // (e.g., "game engine") appears in a library entry's fields, we apply these high-value
  // scores to surface the most relevant results first.
  //
  // For example, a query of "game engine" would match:
  //
  // - Exact match: A tag or search keyword like "game engine"
  // - Prefix match: A title like "Game engine basics"
  // - Substring match: A title like "What is a game engine and what does it do"
  QUERY_EXACT: 450,
  QUERY_PREFIX: 325,
  QUERY_SUBSTRING: 200,

  // Token-based matching: After evaluating the entire search query, we split
  // the query into individual tokens (words) and score each against the title,
  // keywords, tags, and categories.
  TITLE_PREFIX: 100,
  TITLE_WORD: 50,
  TITLE_SUBSTRING: 12,
  KEYWORD_EXACT: 50,
  KEYWORD_PARTIAL: 20,
  TAG_EXACT: 25,
  TAG_PARTIAL: 10,
  CATEGORY_MATCH: 10,

  // Fuzzy matching: When exact and partial matches fail, we calculate a distance
  // to find results even when the user makes typos.
  FUZZY_BASE_SCORE: 12,
} as const;

// This is the minimum score an entry needs to reach to appear in the search
// results. Lower this to get more results, raise it to get fewer but more
// relevant results.
const MIN_SCORE = 4;
// This score is a threshold for how similar two strings must be to be considered
// a match. It allows users to still find relevant results even when they make
// typos in their query. This is a number between 0.0 and 1.0.
// Lower values catch more typos but may produce false positives.
const MIN_TRIGRAM_SIMILARITY = 0.25;
const SUGGESTION_LENGTH_MIN = 2;
const SUGGESTION_LENGTH_MAX = 48;
const SUGGESTION_WORDS_MAX = 6;

/**
 * Normalizes text for consistent searching and matching.
 *
 * We do:
 * 1. NFD normalization: it separates characters with diacritics into their base
 * characters (e.g., é becomes e + the accent mark). This extracts the
 * diacritics.
 * 2. Erase the extracted diacritics, which leaves us with just the base
 * characters.
 * 3. Converts to lowercase so search is case-insensitive.
 *
 * Even though we only have English now, I've added it because:
 * 1. If people write melee it'll match mêlée, which we have in a title
 * 2. If people use borrowed words or mistype something on an international
 * keyboard, it improves the chances of matching.
 */
const normalizeText = (value: string): string =>
  value
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase();

const tokenize = (value: string): string[] =>
  normalizeText(value)
    .split(/[^a-z0-9]+/)
    .filter(Boolean);

const removeDuplicates = (values: string[]): string[] =>
  Array.from(new Set(values));

const normalizeList = (values: string[]): string[] =>
  removeDuplicates(values.map(normalizeText));

const expandWithTokens = (values: string[]): string[] =>
  removeDuplicates(values.flatMap((value) => [value, ...tokenize(value)]));

const humanizeText = (value: string): string =>
  value
    .replace(/[_-]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();

const toSentenceCase = (value: string): string => {
  const humanized = humanizeText(value);
  if (!humanized) {
    return "";
  }
  const lower = humanized.toLowerCase();
  return lower.charAt(0).toUpperCase() + lower.slice(1);
};

/** The public shape returned by `search()`. */
export type SearchResult = {
  item: SearchableItem;
  score: number;
};

/**
 * Map of category -> allowed values, used when filtering results.
 */
export type SearchFilters = Record<string, Set<string>>;

/**
 * Options to pass to the search() and filter() functions.
 * Mainly used to limit the number of results and set a minimum score.
 */
export interface SearchOptions {
  limit?: number;
  minScore?: number;
  filters?: SearchFilters;
}

const FILTER_ONLY_SCORE = 1;

/**
 * Main entry point for the search system. It's returned by the factory function
 * createLibrarySearchEngine().
 */
export interface LibrarySearchEngine {
  search: (query: string, options?: SearchOptions) => SearchResult[];
  filter: (options?: SearchOptions) => SearchResult[];
  suggest: (query: string, limit?: number) => string[];
  total: number;
}

type FilterableFields = {
  entry_type: string;
  format: string[];
  tool_version: string[];
  game_space: string[];
  game_genre: string[];
  subject_tags: string[];
};

/** This stores a token along with its pre-computed trigrams. */
type TokenWithTrigrams = {
  value: string;
  trigrams: Set<string>;
};

/**
 * Cached, normalized representation of a SearchableItem.
 * We normalize and tokenize everything once so we never repeat string work
 * inside tight scoring loops.
 */
type NormalizedSearchEntry = {
  item: SearchableItem;
  title: string;
  titleTokens: string[];
  keywords: string[];
  keywordTokens: string[];
  tags: string[];
  tagTokens: string[];
  categories: string[];
  filterableFields: FilterableFields;
  isArchived: boolean;
  // All phrase values flattened for full-query matching
  allPhraseValues: string[];
  // All tokens with trigrams flattened for fuzzy matching
  allTokensWithTrigrams: TokenWithTrigrams[];
};

/**
 * Generates trigrams from a string. A trigram is a sequence of 3 consecutive characters.
 * For example, "save" produces: ["  s", " sa", "sav", "ave", "ve "]
 * Padding with spaces helps match at word boundaries.
 */
const generateTrigrams = (text: string): Set<string> => {
  const trigrams = new Set<string>();
  const padded = `  ${text} `;
  for (let i = 0; i < padded.length - 2; i += 1) {
    trigrams.add(padded.slice(i, i + 3));
  }
  return trigrams;
};

/**
 * Prepares a raw item for scoring. Everything is normalized and tokenized once so we
 * never repeat string munging work inside tight scoring loops.
 */
const normalizeEntry = (item: SearchableItem): NormalizedSearchEntry => {
  const title = normalizeText(item.title);
  const titleTokens = tokenize(item.title);

  const keywords = normalizeList(item.search);
  const keywordTokens = expandWithTokens(keywords);

  const tags = normalizeList(item.subject_tags);
  const tagTokens = expandWithTokens(tags);

  const categories = normalizeList([
    item.entry_type,
    ...item.format,
    ...item.tool_version,
    ...item.game_space,
    ...item.game_genre,
  ]);

  const filterableFields = {
    entry_type: item.entry_type,
    format: item.format,
    tool_version: item.tool_version,
    game_space: item.game_space,
    game_genre: item.game_genre,
    subject_tags: item.subject_tags,
  };

  const isArchived =
    (item as SearchableItem & { archived?: boolean }).archived ?? false;

  // We flatten all "phrases" to make it easier to match the full query against them
  // Then, we flatten all tokens with pre-computed trigrams for fuzzy matching
  const allPhraseValues = [title, ...keywords, ...tags, ...categories];
  const allTokens = removeDuplicates([
    ...titleTokens,
    ...keywordTokens,
    ...tagTokens,
    ...categories,
  ]);
  const allTokensWithTrigrams = allTokens.map((value) => ({
    value,
    trigrams: generateTrigrams(value),
  }));

  return {
    item,
    title,
    titleTokens,
    keywords,
    keywordTokens,
    tags,
    tagTokens,
    categories,
    filterableFields,
    isArchived,
    allPhraseValues,
    allTokensWithTrigrams,
  };
};

/**
 * Builds suggestion entries during the initial normalization pass.
 * Returns array of [normalizedValue, displayValue] pairs sorted alphabetically.
 */
const buildSuggestionEntries = (
  normalizedEntries: NormalizedSearchEntry[],
): [string, string][] => {
  const pool = new Map<string, string>();

  const addCandidate = (value: string) => {
    if (!value) {
      return;
    }
    const displayValue = toSentenceCase(value);
    if (!displayValue) {
      return;
    }
    const wordCount = displayValue.split(/\s+/).length;
    if (
      displayValue.length > SUGGESTION_LENGTH_MAX ||
      wordCount > SUGGESTION_WORDS_MAX
    ) {
      return;
    }
    const normalizedValue = normalizeText(displayValue);
    if (normalizedValue.length < SUGGESTION_LENGTH_MIN) {
      return;
    }
    if (pool.has(normalizedValue)) {
      return;
    }
    pool.set(normalizedValue, displayValue);
  };

  for (const entry of normalizedEntries) {
    const item = entry.item;
    item.search.forEach(addCandidate);
    item.subject_tags.forEach(addCandidate);
    addCandidate(item.entry_type);
    item.format.forEach(addCandidate);
    item.tool_version.forEach(addCandidate);
    item.game_space.forEach(addCandidate);
    item.game_genre.forEach(addCandidate);
  }

  return Array.from(pool.entries()).sort(([, a], [, b]) => a.localeCompare(b));
};

const CATEGORY_TO_FIELD: Record<string, keyof FilterableFields> = {
  entry_type: "entry_type",
  format: "format",
  tool_version: "tool_version",
  game_space: "game_space",
  game_genre: "game_genre",
  subject_tag: "subject_tags",
  subject_tags: "subject_tags",
};

const matchesFilters = (
  entry: NormalizedSearchEntry,
  filters: SearchFilters,
): boolean => {
  for (const [category, allowedValues] of Object.entries(filters)) {
    if (allowedValues.size === 0) {
      continue;
    }
    const fieldKey = CATEGORY_TO_FIELD[category];
    if (!fieldKey) {
      continue;
    }
    const fieldValue = entry.filterableFields[fieldKey];
    let hasMatch = false;
    if (Array.isArray(fieldValue)) {
      hasMatch = fieldValue.some((value) => allowedValues.has(value));
    } else if (typeof fieldValue === "string") {
      hasMatch = allowedValues.has(fieldValue);
    }
    if (!hasMatch) {
      return false;
    }
  }
  return true;
};

const hasActiveFilters = (filters?: SearchFilters): boolean =>
  !!filters && Object.values(filters).some((set) => set.size > 0);

/**
 * Sorts search results alphabetically by title.
 */
const sortSearchResults = (a: SearchResult, b: SearchResult): number => {
  if (b.score === a.score) {
    return a.item.title.localeCompare(b.item.title);
  }
  return b.score - a.score;
};

const sortByTitle = (a: SearchResult, b: SearchResult): number =>
  a.item.title.localeCompare(b.item.title);

/**
 * Calculates trigram similarity between two pre-computed trigram sets.
 * Returns a value between 0.0 (no similarity) and 1.0 (identical).
 */
const trigramSimilarity = (
  trigramsA: Set<string>,
  trigramsB: Set<string>,
  minSimilarity = MIN_TRIGRAM_SIMILARITY,
): number | null => {
  let intersectionSize = 0;
  for (const trigram of trigramsA) {
    if (trigramsB.has(trigram)) {
      intersectionSize += 1;
    }
  }
  const unionSize = trigramsA.size + trigramsB.size - intersectionSize;
  if (unionSize === 0) {
    return null;
  }
  const similarity = intersectionSize / unionSize;
  return similarity >= minSimilarity ? similarity : null;
};

/**
 * Gives a sizeable score boost when the complete normalized query appears in one of the
 * entry fields. This runs before token-level evaluation so perfect and near-perfect
 * phrase hits always outrank loosely related content.
 */
const evaluateFullQuery = (
  entry: NormalizedSearchEntry,
  normalizedQuery: string,
): number => {
  if (!normalizedQuery) {
    return 0;
  }

  let bestScore = 0;

  for (const candidate of entry.allPhraseValues) {
    if (!candidate) {
      continue;
    }
    if (candidate === normalizedQuery) {
      return SCORE.QUERY_EXACT;
    }
    if (candidate.startsWith(normalizedQuery)) {
      if (SCORE.QUERY_PREFIX > bestScore) {
        bestScore = SCORE.QUERY_PREFIX;
      }
    } else if (candidate.includes(normalizedQuery)) {
      if (SCORE.QUERY_SUBSTRING > bestScore) {
        bestScore = SCORE.QUERY_SUBSTRING;
      }
    }
  }

  return bestScore;
};

/**
 * Scores a single token against the various fields (title, keywords, tags, categories),
 * falling back to typo tolerance when nothing else matches.
 */
const evaluateToken = (
  entry: NormalizedSearchEntry,
  token: string,
  queryTrigrams: Set<string>,
): number => {
  let bestScore = 0;

  // Match against the title first
  if (entry.title.startsWith(token)) {
    bestScore = SCORE.TITLE_PREFIX;
  } else if (entry.titleTokens.some((word) => word.startsWith(token))) {
    bestScore = SCORE.TITLE_WORD;
  } else if (entry.title.includes(token)) {
    bestScore = SCORE.TITLE_SUBSTRING;
  }

  // Then check the tags
  if (entry.tags.includes(token)) {
    if (SCORE.TAG_EXACT > bestScore) {
      bestScore = SCORE.TAG_EXACT;
    }
  } else if (entry.tagTokens.some((tag) => tag.startsWith(token))) {
    if (SCORE.TAG_PARTIAL > bestScore) {
      bestScore = SCORE.TAG_PARTIAL;
    }
  } else if (entry.tagTokens.some((tag) => tag.includes(token))) {
    const score = SCORE.TAG_PARTIAL - 20;
    if (score > bestScore) {
      bestScore = score;
    }
  }

  // Check keywords
  if (entry.keywords.includes(token)) {
    if (SCORE.KEYWORD_EXACT > bestScore) {
      bestScore = SCORE.KEYWORD_EXACT;
    }
  } else if (entry.keywordTokens.some((kw) => kw.startsWith(token))) {
    if (SCORE.KEYWORD_PARTIAL > bestScore) {
      bestScore = SCORE.KEYWORD_PARTIAL;
    }
  } else if (entry.keywordTokens.some((kw) => kw.includes(token))) {
    const score = SCORE.KEYWORD_PARTIAL - 20;
    if (score > bestScore) {
      bestScore = score;
    }
  }

  if (entry.categories.includes(token)) {
    if (SCORE.CATEGORY_MATCH > bestScore) {
      bestScore = SCORE.CATEGORY_MATCH;
    }
  } else if (entry.categories.some((cat) => cat.includes(token))) {
    if (SCORE.CATEGORY_MATCH > bestScore) {
      bestScore = SCORE.CATEGORY_MATCH;
    }
  }

  // We only use fuzzy matching if nothing else that has more weight matched (no
  // need to check for typos if we have a strong match for this token already)
  if (bestScore === 0) {
    // Short tokens get a stricter similarity threshold so typos don't match too
    // easily (this is to avoid false positives)
    const minSimilarity = token.length >= 5 ? MIN_TRIGRAM_SIMILARITY : 0.5;

    for (const candidate of entry.allTokensWithTrigrams) {
      const similarity = trigramSimilarity(
        candidate.trigrams,
        queryTrigrams,
        minSimilarity,
      );
      if (similarity == null) {
        continue;
      }
      const normalizedSimilarity = (similarity - minSimilarity) /
        (1.0 - minSimilarity);
      const typoScore = Math.floor(
        SCORE.FUZZY_BASE_SCORE * (0.5 + normalizedSimilarity * 0.5),
      );
      if (typoScore > bestScore) {
        bestScore = typoScore;
      }
    }
  }

  return bestScore;
};

/**
 * Calculates the final score for an entry, combining phrase-level bonuses and per-token hits.
 */
const scoreEntry = (
  entry: NormalizedSearchEntry,
  tokens: string[],
  tokenTrigrams: Set<string>[],
  normalizedQuery: string,
): number | null => {
  let total = evaluateFullQuery(entry, normalizedQuery);

  for (let i = 0; i < tokens.length; i++) {
    const tokenScore = evaluateToken(entry, tokens[i], tokenTrigrams[i]);
    if (tokenScore === 0) {
      return null;
    }
    total += tokenScore;
  }

  return total === 0 ? null : total;
};

/**
 * Public factory that accepts the raw `SearchableItem` array and returns handy helpers
 * for searching, filtering, and generating query suggestions.
 */
export const createLibrarySearchEngine = (
  items: SearchableItem[],
): LibrarySearchEngine => {
  const normalized = items.map(normalizeEntry);
  const suggestionEntries = buildSuggestionEntries(normalized);

  const filter = (options: SearchOptions = {}): SearchResult[] => {
    const filters = options.filters;
    if (!hasActiveFilters(filters) || !filters) {
      return [];
    }
    const results: SearchResult[] = [];
    for (const entry of normalized) {
      if (matchesFilters(entry, filters)) {
        results.push({ item: entry.item, score: FILTER_ONLY_SCORE });
      }
    }
    results.sort(sortByTitle);
    if (typeof options.limit === "number" && options.limit > 0) {
      return results.slice(0, options.limit);
    }
    return results;
  };

  const search = (
    query: string,
    options: SearchOptions = {},
  ): SearchResult[] => {
    const sanitized = query.trim();
    const filters = options.filters;
    const filtersEnabled = hasActiveFilters(filters);

    if (!sanitized) {
      return filtersEnabled ? filter(options) : [];
    }
    const normalizedQuery = normalizeText(sanitized);
    if (!normalizedQuery) {
      return filtersEnabled ? filter(options) : [];
    }
    const tokens = tokenize(sanitized);
    if (tokens.length === 0) {
      return filtersEnabled ? filter(options) : [];
    }

    // Pre-compute trigrams for all query tokens once
    const tokenTrigrams = tokens.map(generateTrigrams);

    const minScore = options.minScore ?? MIN_SCORE;
    const activeResults: SearchResult[] = [];
    const archivedResults: SearchResult[] = [];

    for (const entry of normalized) {
      if (filtersEnabled && filters && !matchesFilters(entry, filters)) {
        continue;
      }
      const score = scoreEntry(entry, tokens, tokenTrigrams, normalizedQuery);
      if (score != null && score >= minScore) {
        const result = { item: entry.item, score };
        const scoreFactor = (
          // lower glossary entries
          entry.item.isGlossaryEntry
            ? 0.7
            // lower youtube shorts
            : entry.item.isYoutubeShort
            ? 0.5
            // anything not Godot 4: lower too
            : !entry.item.tool_version.includes("godot_4")
            ? 0.8
            : 1.0
        );
        result.score = result.score * scoreFactor;
        if (entry.isArchived) {
          archivedResults.push(result);
        } else {
          activeResults.push(result);
        }
      }
    }

    // Sort each bucket independently, then append glossary and archived into
    // activeResults in-place to avoid allocating a fourth combined array.
    activeResults.sort(sortSearchResults);
    archivedResults.sort(sortSearchResults);
    for (const result of archivedResults) {
      activeResults.push(result);
    }

    if (typeof options.limit === "number" && options.limit > 0) {
      return activeResults.slice(0, options.limit);
    }
    return activeResults;
  };

  const suggest = (query: string, limit = 6): string[] => {
    if (limit <= 0) {
      return [];
    }
    const sanitized = query.trim();
    if (!sanitized) {
      return [];
    }
    const normalizedQuery = normalizeText(sanitized);
    if (!normalizedQuery) {
      return [];
    }

    const prefixMatches: string[] = [];
    const substringMatches: string[] = [];

    for (const [normalizedValue, displayValue] of suggestionEntries) {
      if (normalizedValue.startsWith(normalizedQuery)) {
        prefixMatches.push(displayValue);
      } else if (normalizedValue.includes(normalizedQuery)) {
        substringMatches.push(displayValue);
      }
      if (prefixMatches.length >= limit) {
        break;
      }
    }

    if (prefixMatches.length < limit) {
      for (const suggestion of substringMatches) {
        prefixMatches.push(suggestion);
        if (prefixMatches.length >= limit) {
          break;
        }
      }
    }

    return prefixMatches.slice(0, limit);
  };

  return { search, filter, suggest, total: normalized.length };
};

export type GlossarySearchItem = { slug: string; terms: string[] };

export type GlossarySearchResult = {
  slug: string;
  terms: string[];
  score: number;
};

export interface GlossarySearchEngine {
  search: (query: string, options?: SearchOptions) => GlossarySearchResult[];
  total: number;
}

const normalizeGlossaryItem = (item: GlossarySearchItem) => ({
  slug: item.slug,
  terms: item.terms.map((term) => ({
    raw: term,
    normalized: normalizeText(term),
    tokens: tokenize(term),
  })),
});

export const createGlossarySearchEngine = (
  items: GlossarySearchItem[],
): GlossarySearchEngine => {
  const normalized = items.map(normalizeGlossaryItem);

  const search = (
    query: string,
    options: SearchOptions = {},
  ): GlossarySearchResult[] => {
    const sanitized = query.trim();
    if (!sanitized) {
      return [];
    }
    const token = normalizeText(sanitized);
    const tokenTrigrams = generateTrigrams(token);
    const minScore = options.minScore ?? MIN_SCORE;
    const results: GlossarySearchResult[] = [];

    for (const entry of normalized) {
      let bestScore = 0;
      for (const term of entry.terms) {
        if (term.normalized.startsWith(token)) {
          bestScore = SCORE.TAG_EXACT;
          break;
        }
        if (term.tokens.some((value) => value.startsWith(token))) {
          bestScore = Math.max(bestScore, SCORE.TAG_PARTIAL);
        } else if (term.normalized.includes(token)) {
          bestScore = Math.max(bestScore, SCORE.KEYWORD_PARTIAL);
        } else {
          const termTrigrams = generateTrigrams(term.normalized);
          const similarity = trigramSimilarity(termTrigrams, tokenTrigrams);
          if (similarity != null) {
            const typoScore = Math.floor(SCORE.FUZZY_BASE_SCORE * similarity);
            bestScore = Math.max(bestScore, typoScore);
          }
        }
      }
      if (bestScore >= minScore) {
        results.push({
          slug: entry.slug,
          terms: entry.terms.map((t) => t.raw),
          score: bestScore,
        });
      }
    }

    results.sort((a, b) => {
      if (b.score === a.score) {
        return a.slug.localeCompare(b.slug);
      }
      return b.score - a.score;
    });

    if (typeof options.limit === "number" && options.limit > 0) {
      return results.slice(0, options.limit);
    }
    return results;
  };

  return { search, total: normalized.length };
};
