import * as constants from "./tableOfContentsConsts.ts";
import type { ToggleShowEvent } from "./togglerButton.client.ts";
import {
  onScrollStopped,
  processDomElementOnce,
  scrollIntoViewIfPartiallyVisible,
} from "../clientScript/clientDependencies.ts";
import { getViewPortSizeFromCss } from "../clientScript/getViewPortSizeFromCss.ts";

type HeadingAnchor = HTMLAnchorElement & {
  heading: HTMLElement;
  closestRevealButton?: HTMLButtonElement | null;
  setIsScrolledPast: (isScrolledPast: boolean) => void;
  setIsCurrent: (isCurrent: boolean) => void;
  scrollingParent: HTMLElement;
  root: HTMLElement;
};

function setIsScrolledPast(this: HeadingAnchor, isScrolledPast: boolean) {
  if (isScrolledPast) {
    this.classList.add(constants.CLASS_ANCHOR_SCROLLED_PAST);
  } else {
    this.classList.remove(constants.CLASS_ANCHOR_SCROLLED_PAST);
  }
}

function setIsCurrent(this: HeadingAnchor, isCurrent: boolean) {
  const parent = this.parentElement as HTMLLIElement;
  if (isCurrent) {
    parent.classList.add(constants.CLASS_CURRENT_LIST_ITEM);
    scrollIntoViewIfPartiallyVisible(parent, this.scrollingParent);
    const revealButton = this.closestRevealButton;
    if (
      revealButton && revealButton.getAttribute("aria-expanded") === "false"
    ) {
      revealButton.click();
    }
  } else {
    parent.classList.remove(constants.CLASS_CURRENT_LIST_ITEM);
  }
}

const sortDomElementsByVerticalPosition = (a: string, b: string) =>
  (document.getElementById(a)?.getBoundingClientRect().top ?? 0) -
  (document.getElementById(b)?.getBoundingClientRect().top ?? 0);

const getDirectChildButton = (element: HTMLElement | null) => {
  return element &&
    (Array.from(element.children).find((child) =>
      child.matches(
        `button.${constants.CLASS_FOLD_UNFOLD_BUTTON}`,
      )
    ) as HTMLButtonElement | null);
};

processDomElementOnce('[data-is="article-toc"]', (root: HTMLElement) => {
  /** All observed headings */
  const headings: HTMLHeadingElement[] = [];
  /** List of all headings ids */
  const headingsIds: string[] = [];
  const anchors = new Map<string, HeadingAnchor>();

  const scrollingParent = root.closest<HTMLElement>(
    `.${constants.CLASS_SCROLLING_PANE}`,
  );

  if (!scrollingParent) {
    throw new Error("Scrolling parent not found");
  }

  const removeAllCurrent = () =>
    root
      .querySelectorAll(`.${constants.CLASS_CURRENT_LIST_ITEM}`)
      .forEach((el) => el.classList.remove(constants.CLASS_CURRENT_LIST_ITEM));

  let suspendObserverUpdates = false;

  function anchorClicked(this: HeadingAnchor) {
    removeAllCurrent();
    setIsCurrent.call(this, true);
    suspendObserverUpdates = true;
    onScrollStopped(() => {
      suspendObserverUpdates = false;
      setIsCurrent.call(this, true); // this needs to be called again because of a race between scroll stopped and observer
    });
  }

  root.querySelectorAll<HeadingAnchor>(
    `a.${constants.CLASS_ANCHOR_LINK}[href^="#"]`,
  )
    .forEach((anchor) => {
      const href = anchor.getAttribute("href");
      if (!href) return;
      const heading = document.querySelector<HTMLHeadingElement>(href);
      if (!heading) return;
      const id = href.slice(1);
      headingsIds.push(id);
      headings.push(heading);
      anchor.heading = heading;
      anchors.set(id, anchor);
      anchor.setIsScrolledPast = setIsScrolledPast;
      anchor.setIsCurrent = setIsCurrent;
      anchor.scrollingParent = scrollingParent;
      anchor.addEventListener("click", anchorClicked);
    });

  const revealButtons = new Set<HTMLButtonElement>();

  anchors.forEach((anchor) => {
    let currentElement: HTMLLIElement | null | undefined = anchor
      .parentElement as HTMLLIElement;
    while (currentElement) {
      const revealButton = getDirectChildButton(currentElement);
      if (revealButton != null) {
        anchor.closestRevealButton = revealButton;
        revealButtons.add(revealButton);
        return;
      }
      currentElement = currentElement.parentElement?.closest("li");
    }
  });

  /** list of active headings ids */
  const active: string[] = [];

  const observer = new IntersectionObserver(
    (entries) => {
      // collect headings in view
      entries.forEach((entry) => {
        if (entry.isIntersecting && entry.intersectionRatio > 0) {
          active.push(entry.target.id);
        } else {
          const index = active.indexOf(entry.target.id);
          if (index > -1) {
            active.splice(index, 1);
          }
        }
      });

      // if no headings are active, exit early
      if (active.length === 0) {
        return;
      }
      // get the highest in viewport
      const primaryActiveId = active.sort(sortDomElementsByVerticalPosition).at(
        0,
      );

      let reachedCurrent = false;

      if (suspendObserverUpdates === false) {
        removeAllCurrent();
      }

      for (const [id, anchor] of anchors) {
        if (reachedCurrent || id === primaryActiveId) {
          if (id === primaryActiveId) {
            reachedCurrent = true;
            anchor.setIsScrolledPast(true);
            if (suspendObserverUpdates === false) {
              anchor.setIsCurrent(true);
            }
          } else {
            anchor.setIsScrolledPast(false);
          }
        } else {
          anchor.setIsScrolledPast(true);
        }
      }
    },
    { rootMargin: "0% 0% -10% 0%" },
  );
  headings.forEach((h) => observer.observe(h));
});

processDomElementOnce(
  `#${constants.classPrefix}Wrapper button.${constants.classPrefix}ToggleButton`,
  (button: HTMLButtonElement) => {
    // By default, the navigation is shown until the toggle is pressed, but on mobile,
    // the navigation is hidden by default.
    // We will do a media query that checks if there's enough space for the navigation to be shown.
    // If not, we programmatically press the toggle button to hide the navigation.

    const target = document.getElementById(
      button.getAttribute("aria-controls")!,
    );

    if (!target) {
      return;
    }
    button.addEventListener("toggler-toggleshow", (event: ToggleShowEvent) => {
      document.documentElement.classList.toggle(
        constants.SIDEBAR_CLOSED_BODY_CLASS,
        event.isHidden,
      );
    });

    // trick to get CSS to tell it size; the `content` property of the
    // `after` pseudo-element is changed depending on media queries.
    const size = getViewPortSizeFromCss();
    if (size === "viewport-mobile") {
      button.click();
    }
  },
);
