interface QuerySelectorAllOptions {
  /**
   * The parent element to search within. Defaults to the document. If explicit `null` is passed, the function
   * is short-circuited to return `null` immediately.
   */
  parent?: Element | Document | null;
  /** Callback invoked when no element is found. Defaults to `console.warn`. Set it to `false` to disable the warning. */
  onNotFound?:
    | ((selector: string, parent: Element | Document | null) => void)
    | false;
}

/**
 * Thin wrapper around `Element.querySelectorAll` with added features.
 * Queries the DOM for all elements matching the given selector.
 *
 * **Note**: This function assumes the element is of type `HTMLElement` when not specified.
 * The original `querySelector` can return regular `Element` nodes;
 * this function can too, but makes an assumption that's convenient, even if it reduces
 * type safety.
 *
 * **Note 2**: Unlike `querySelector`, this function returns:
 * - `null` if no elements are found
 * - an array of elements and **not** a `NodeListOf<Element>`.
 *
 * Mind those differences.
 * @param selector The CSS selector to match.
 * @param options Optional parameters for the query.
 * @returns An array of matching elements, or `null` if no matches are found.
 */
export function querySelectorAll<K extends keyof HTMLElementTagNameMap>(
  selectors: K,
  options?: QuerySelectorAllOptions
): HTMLElementTagNameMap[K][];
export function querySelectorAll<K extends keyof SVGElementTagNameMap>(
  selectors: K,
  options?: QuerySelectorAllOptions
): SVGElementTagNameMap[K][];
export function querySelectorAll<K extends keyof MathMLElementTagNameMap>(
  selectors: K,
  options?: QuerySelectorAllOptions
): MathMLElementTagNameMap[K][];
export function querySelectorAll<E extends HTMLElement = HTMLElement>(
  selectors: string,
  options?: QuerySelectorAllOptions
): E[];
export function querySelectorAll<E extends HTMLElement = HTMLElement>(
  selector: string,
  options?: QuerySelectorAllOptions
): E[] | null {
  const parent = options?.parent === null ? null : options?.parent ?? document;
  const elements =
    parent === null ? [] : (parent.querySelectorAll(selector) as NodeListOf<E>);
  if (elements.length === 0) {
    if (options?.onNotFound) {
      options.onNotFound(selector, parent);
    } else if (options?.onNotFound !== false) {
      console.warn(
        `Didn't find any element for selector \`${selector}\` in`,
        parent
      );
    }
    return null;
  }
  return Array.from(elements);
}
