interface QuerySelectorOptions {
  /**
   * The parent element to search within. Defaults to the document. If explicit `null` is passed, the function
   * is short-circuited to return `null` immediately.
   */
  parent?: Element | Document | null;
  /** Callback invoked when no element is found. Defaults to `console.warn`. Set it to `false` to disable the warning. */
  onNotFound?:
    | ((selector: string, parent: Element | Document | null) => void)
    | false;
}

/**
 * Thin wrapper around `Element.querySelector` with added features.
 * Queries the DOM for a single element matching the given selector.
 *
 * **Note**: This function assumes the element is of type `HTMLElement` when not specified.
 * The original `querySelector` can return regular `Element` nodes;
 * this function can too, but makes an assumption that's convenient, even if it reduces
 * type safety.
 * @param selector The CSS selector to match.
 * @param options Optional parameters for the query.
 * @returns The first matching element, or null if no match is found.
 */
export function querySelector<K extends keyof HTMLElementTagNameMap>(
  selectors: K,
  options?: QuerySelectorOptions
): HTMLElementTagNameMap[K] | null;
export function querySelector<K extends keyof SVGElementTagNameMap>(
  selectors: K,
  options?: QuerySelectorOptions
): SVGElementTagNameMap[K] | null;
export function querySelector<K extends keyof MathMLElementTagNameMap>(
  selectors: K,
  options?: QuerySelectorOptions
): MathMLElementTagNameMap[K] | null;
export function querySelector<E extends HTMLElement = HTMLElement>(
  selectors: string,
  options?: QuerySelectorOptions
): E | null;
export function querySelector<E extends HTMLElement>(
  selector: string,
  options?: QuerySelectorOptions
): E | null {
  const parent = options?.parent === null ? null : options?.parent ?? document;
  const element =
    parent === null ? null : (parent.querySelector(selector) as E | null);
  if (element === null) {
    if (options?.onNotFound) {
      options.onNotFound(selector, parent);
    } else if (options?.onNotFound !== false) {
      console.warn(`Element not found: \`${selector}\` in`, parent);
    }
  }
  return element;
}
