import { processDomElementOnce, createShaderPreview, type TextureOptions } from "../clientScript/clientDependencies.ts";

export interface ShaderTexture {
  src: string | undefined;
  options: TextureOptions;
}

processDomElementOnce<HTMLElement>(".ShaderPreview", (wrapper) => {
  const canvas = wrapper.querySelector<HTMLCanvasElement>(
    ".ShaderPreviewCanvas",
  );
  if (!canvas) return;
  
  const codeElement = wrapper.querySelector(".ShaderPreviewChildren pre > code.language-gdshader");
  const shader = wrapper.dataset.shader || codeElement?.textContent || "";
  
  const controlsContainer = wrapper.querySelector(".ShaderPreviewControls");

  // Collect images
  // name="" -> image is provided as the TEXTURE built-in in the shader
  // name="uniform_name" -> if a uniform called 'uniform_name' exists, it will use this image

  let mainTexture: ShaderTexture = {
    src: undefined,
    options: {
      filter: "linear",
      repeat: "disabled"
    }
  };
  const extraTextures: Record<string, ShaderTexture> = {};

  for (const img of wrapper.querySelectorAll<HTMLImageElement>(
    ".ShaderPreviewChildren img",
  )) {
    const filter = img.dataset.filter as TextureOptions["filter"] | undefined;
    const repeat = img.dataset.repeat as TextureOptions["repeat"] | undefined;

    const texture: ShaderTexture = {
      src: img.src,
      options: {
        filter: filter ?? "linear",
        repeat: repeat ?? "disabled",
      },
    }

    if (!img.name) {
      mainTexture = texture
    } else {
      extraTextures[img.name] = texture;
    }
  }

  createShaderPreview(
    canvas,
    shader,
    {
      mainTexture,
      extraTextures,
      codeElement: codeElement ?? undefined,
      controlsContainer: controlsContainer ?? undefined,
    },
  );

  // After input sliders generate, their adjacent label updates on slider move
  for (
    const input of wrapper.querySelectorAll<HTMLInputElement>(
      "input[type='range']",
    )
  ) {
    const output = input.nextElementSibling as HTMLOutputElement | null;
    if (output) {
      input.addEventListener("input", () => {
        output.value = input.value;
      });
    }
  }
});
