import {
  h,
  processDomElementOnce,
} from "../clientScript/clientDependencies.ts";

const { a, span, add } = h;

const pageTitle = (document.body.querySelector("main h1")?.textContent ?? "")
  .trim();
const pageUrl = new URL(globalThis.location.href);
pageUrl.hash = "";

processDomElementOnce<HTMLElement>(
  `main.prose h1, main.prose h2, main.prose h3`,
  (element) => {
    const anchor = element.id;
    if (!anchor) return;
    element.classList.add("anchorClipboardButtonInvoker");
    const title = element.textContent?.trim() ?? "";
    const dataClipboard = `${pageTitle} - ${title}: ${pageUrl}#${anchor}`;
    const clipboardButton = a({
      className: `anchorClipboardButton`,
      dataIs: "clipboard-button",
      href: `#${anchor}`,
      dataClipboard,
    }, span(`Click to copy`));
    clipboardButton.addEventListener("click", (event) => {
      event.preventDefault();
      if (history.pushState) history.pushState(null, "unused", `#${anchor}`);
    });
    add(element, clipboardButton);
  },
  `js-processed-anchorClipboardButtonInvoker`,
);
