import { Signal } from "./clientDependencies.ts";

interface ScrollSpyOptions {
  scrollElement: HTMLElement | Document;
  granularity?: number;
}

const createScrollSpy = ({
  scrollElement,
  granularity = 10,
}: ScrollSpyOptions) => {
  const snappedScrollY = Signal(0);

  scrollElement.addEventListener(
    "scroll",
    //debounce(
    () => {
      const scrollY = scrollElement instanceof HTMLElement
        ? scrollElement.scrollTop
        : globalThis.scrollY;
      const snapped = Math.round(scrollY / granularity) * granularity;
      if (snappedScrollY.get() !== snapped) {
        snappedScrollY.set(snapped);
      }
    },
    //, debounceDelay),
  );
  return snappedScrollY;
};

interface ScrollSpyUpdateCustomPropsOptions extends ScrollSpyOptions {
  recipient: HTMLElement;
}

const getViewportHeight = () =>
  Math.max(
    document.documentElement.clientHeight || 1,
    globalThis.innerHeight || 1,
  );

const dataScrollSnappedAttr = "data-scroll-y-is-snapped";
const dataScrolledAtLeastOnce = "data-scrolled-at-least-once";

const updateCustomPropOnScroll = ({
  recipient,
  ...rest
}: ScrollSpyUpdateCustomPropsOptions) => {
  const snappedScrollY = createScrollSpy(rest);
  let viewportHeight = getViewportHeight();
  globalThis.addEventListener(
    "resize",
    () => (viewportHeight = getViewportHeight()),
  );

  recipient.classList.add("isListeningToScroll");

  let wasScrolled = false;
  let previousScreenStep = 0;
  const update = () => {
    const scrollY = snappedScrollY.get();
    const isScrolled = scrollY > 0;
    if (isScrolled !== wasScrolled) {
      wasScrolled = isScrolled;
      if (isScrolled) {
        recipient.setAttribute(dataScrollSnappedAttr, "");
        recipient.setAttribute(dataScrolledAtLeastOnce, "");
      } else {
        recipient.removeAttribute(dataScrollSnappedAttr);
        recipient.removeAttribute("data-scrolled-screens");
        previousScreenStep = 0;
      }
    }
    if (isScrolled) {
      const scrolledScreens = Math.max(
        0.5,
        Math.round((scrollY / viewportHeight) * 2) / 2,
      );
      if (scrolledScreens > 0 && scrolledScreens !== previousScreenStep) {
        previousScreenStep = scrolledScreens;
        recipient.setAttribute("data-scrolled-screens", `${scrolledScreens}`);
      }
    }
  };

  let requestFrameId = 0;

  const scheduleUpdate = () => {
    if (!requestFrameId) {
      requestFrameId = requestAnimationFrame(() => {
        requestFrameId = 0;
        update();
      });
    }
  };
  snappedScrollY.on(scheduleUpdate);
  update();
};

updateCustomPropOnScroll({
  scrollElement: document,
  recipient: document.documentElement,
});
