import {
  debounce,
  FetcherSignal,
  type GlossaryDictionaryKeys,
  processDomElementOnce,
} from "../clientScript/clientDependencies.ts";
import {
  createGlossarySearchEngine,
  type GlossarySearchItem,
} from "../clientScript/searchEngine.ts";

const classPrefixSearch = "glossarySearch";
const classPrefixList = "glossaryList";

function setElementDisabled(this: HTMLElement, doDisable: boolean) {
  if (doDisable) {
    this.classList.add("disabled");
    this.setAttribute("aria-disabled", "true");
    this.setAttribute("hidden", "true");
    this.setAttribute("tabindex", "-1");
    this.dataset.href = this.getAttribute("href") ?? "";
    this.removeAttribute("href");
  } else {
    this.classList.remove("disabled");
    this.removeAttribute("aria-disabled");
    this.removeAttribute("hidden");
    this.removeAttribute("tabindex");
    if (this.dataset.href) {
      this.setAttribute("href", this.dataset.href);
      delete this.dataset.href;
    }
  }
}

processDomElementOnce(`.${classPrefixSearch}`, (element) => {
  const form = element.querySelector("form");
  if (!form) {
    console.error("No form found in glossary search component");
    return;
  }

  form.addEventListener("submit", (event) => {
    event.preventDefault();
  });

  const input = form.querySelector("input[type='search']") as HTMLInputElement;
  if (!input) {
    console.error("No input found in glossary search component");
    return;
  }

  const noSearchResultsElement = document.querySelector(
    `#${classPrefixList}NothingFound`,
  ) as HTMLLIElement;
  if (!noSearchResultsElement) {
    console.error(
      "No element with ID glossaryListNothingFound found in glossary search component",
    );
    return;
  }

  const dataURL = element.dataset.searchUrl;
  if (!dataURL) {
    console.error(
      "No data-fuse-url attribute found in glossary search component",
    );
    return;
  }

  const searchTerms = new Map(
    Array.from(
      document.querySelectorAll<HTMLLIElement>(
        `.${classPrefixList} li.${classPrefixList}TermItem[data-slug]`,
      ),
    ).map((el) => {
      const slug = el.dataset.slug!;
      return [slug, el] as const;
    }),
  );

  const tocAnchors = new Map(
    Array.from(document.querySelectorAll<HTMLAnchorElement>(
      "#tableOfContentsPane a.tableOfContentsAnchorLinkToH2[href^='#glossary-letter-']",
    )).map((a) => {
      const letter = a.getAttribute("href")!.replace("#glossary-letter-", "");
      const augmentedAnchor = a as HTMLAnchorElement & {
        setAnchorDisabled: (doDisable: boolean) => void;
      };
      augmentedAnchor.setAnchorDisabled = setElementDisabled;
      return [letter, augmentedAnchor] as const;
    }),
  );

  const searchInputAnchors = new Map(
    Array.from(
      element.querySelectorAll<HTMLAnchorElement>(
        ".glossarySearchJumpLinks a",
      ),
    ).map((a) => {
      const letter = a.getAttribute("href")!.replace("#glossary-letter-", "");
      const augmentedAnchor = a as HTMLAnchorElement & {
        setAnchorDisabled: (doDisable: boolean) => void;
      };
      augmentedAnchor.setAnchorDisabled = setElementDisabled;
      return [letter, augmentedAnchor] as const;
    }),
  );

  const sections = new Map(
    Array.from(
      document.querySelectorAll<HTMLLIElement>(
        "#glossaryList li[id^='glossarySection-letter-'][data-letter]",
      ),
    ).map((section) => {
      const letter = section.dataset.letter! as GlossaryDictionaryKeys;
      const element = section as HTMLLIElement & {
        setSectionDisabled: (doDisable: boolean) => void;
      };
      element.setSectionDisabled = setElementDisabled;
      return [letter, element] as const;
    }),
  );

  type Data = {
    items: GlossarySearchItem[];
    metadata: {
      version: number;
      generatedAt: string;
    };
  };

  const onSearchLoaded = (data: Data) => {
    const engine = createGlossarySearchEngine(data.items);
    const onInputEnter = debounce(() => {
      const query = input.value.trim();
      if (query.length === 0) {
        tocAnchors.forEach((a) => a.setAnchorDisabled(false));
        searchInputAnchors.forEach((a) => a.setAnchorDisabled(false));
        sections.forEach((s) => s.setSectionDisabled(false));
        noSearchResultsElement.hidden = true;
        searchTerms.forEach((term) => term.removeAttribute("hidden"));
        return;
      }
      const results = engine.search(query);
      tocAnchors.forEach((a) => a.setAnchorDisabled(true));
      searchInputAnchors.forEach((a) => a.setAnchorDisabled(true));
      sections.forEach((s) => s.setSectionDisabled(true));
      noSearchResultsElement.hidden = results.length > 0;
      searchTerms.forEach((term) => term.setAttribute("hidden", "true"));
      if (results.length > 0) {
        results.forEach(({ slug, terms }) => {
          searchTerms.get(slug)?.removeAttribute("hidden");
          const firstTerm = terms[0] ?? "";
          const letter = firstTerm.charAt(0).toLocaleUpperCase();
          const key =
            (letter.match(/[0-9]/) ? "1-9" : letter) as GlossaryDictionaryKeys;
          tocAnchors.get(key)?.setAnchorDisabled(false);
          searchInputAnchors.get(key)?.setAnchorDisabled(false);
          sections.get(key)?.setSectionDisabled(false);
        });
      }
    }, 150);

    input.addEventListener("input", onInputEnter);
    if (input.value.trim().length > 0) {
      onInputEnter();
    }
  };

  const searchLoadedData = FetcherSignal<Data>();

  searchLoadedData.on(({ status, data }) => {
    if (status === "success") {
      onSearchLoaded(data);
    }
  });

  searchLoadedData.load(dataURL);
});
