import { getElementRelativePosition } from "./getElementRelativePosition.ts";
import { isRelativePositionPartiallyWithinParent } from "./isElementPartiallyVisibleInParent.ts";

/**
 * Scrolls element into view only if it's not already visible
 * @param element - Element to scroll into view
 * @param scrollableParent - Scrollable parent container
 * @returns true if element was scrolled into view, false otherwise
 */
export const scrollIntoViewIfPartiallyVisible = (
  element: HTMLElement,
  scrollableParent: HTMLElement,
): boolean => {
  const relative = getElementRelativePosition(element, scrollableParent);
  const isPartiallyVisible = isRelativePositionPartiallyWithinParent(relative);

  if (isPartiallyVisible) {
    return false;
  }

  if (relative.top < 0) {
    // Scroll element to top if requested or if element is above viewport
    scrollableParent.scrollTop += relative.top;
  } else {
    // Scroll element to bottom if it's below viewport
    scrollableParent.scrollTop += relative.top - relative.parentHeight +
      relative.height;
  }
  return true;
};
