// Determines the viewport size based on CSS media queries by reading the content of the body:before pseudo-element.
// see: web-components/clientStyles/contentGrid.scss
type ViewPortSize =
  | "viewport-mobile"
  | "viewport-tablet"
  | "viewport-desktop";

/**
 * Determines if the page is being viewed on mobile, tablet, or desktop.
 * To avoid trying to sync with CSS media queries in multiple places,
 * this function reads the `content` property of the `body:before` pseudo-element,
 * which is set via CSS media queries.
 *
 * This of course requires that the CSS is set up to do this. Something like:
 * ```css
 * &::before {
 * 	content: "viewport-small";
 * }
 * @media (min-width: $tablet-breakpoint) {
 * 	&::before {
 * 		content: "viewport-tablet";
 * 	}
 * }
 * @media (min-width: $mid-breakpoint) {
 *   ... and so on
 * ```
 * If the CSS is not set up this way, the function falls back to a simple
 * media query based on the `fallBackMaxWidth` parameter.
 *
 * @param fallBackMaxWidth - The max width in pixels to consider as mobile for the fallback media query. Default is 1080.
 */
export const getViewPortSizeFromCss = (
  fallBackMaxWidth = 1080,
): ViewPortSize => {
  const size = (getComputedStyle(document.body, ":before")?.getPropertyValue(
    "content",
  ) ?? "").slice(1, -1).trim() as
    | "viewport-mobile"
    | "viewport-tablet"
    | "viewport-desktop"
    | ""
    | undefined;

  if (!size) {
    // fallback to media query -- this should match the ContentGrid queries
    if (globalThis.matchMedia(`(max-width: ${fallBackMaxWidth}px)`).matches) {
      return "viewport-mobile";
    }
    return "viewport-desktop";
  }
  return size;
};
