import {
  debounce,
  makeLogger,
  processDomElementOnce,
} from "../clientScript/clientDependencies.ts";

const logger = makeLogger("ScrollingList");

/**
 * Enhances a grid container with slider functionality
 * @param slider the main container element
 */
processDomElementOnce(".scrollingList", (slider: Element) => {
  const grid = slider.querySelector<HTMLElement>(".gridItemsList");
  const controls = slider.querySelector<HTMLElement>(".scrollingListControls");
  const prevButton = slider.querySelector<HTMLButtonElement>(
    ".scrollingListControlsPrevious",
  );
  const nextButton = slider.querySelector<HTMLButtonElement>(
    ".scrollingListControlsNext",
  );

  if (!grid || !controls || !prevButton || !nextButton) {
    logger.warn(
      "ScrollingList: Missing required elements. Ensure the grid and controls are present.",
      { grid, controls, prevButton, nextButton },
    );
    return;
  }

  let carouselWindowWidth = 0;
  let pages = 0;
  let currentPage = 0;

  const init = () => {
    controls.removeAttribute("hidden");
    slider.classList.add("isScrolling");
    slider.ariaRoleDescription = "carousel";

    prevButton.addEventListener("click", () => navigate(-1));
    nextButton.addEventListener("click", () => navigate(1));

    globalThis.addEventListener("resize", debounce(calculateAndNavigate));

    grid.addEventListener("scrollend", calculateDimensions);

    calculateDimensions();
  };

  const calculateDimensions = () => {
    carouselWindowWidth = grid.offsetWidth;
    const carouselInnerWidth = grid.scrollWidth;
    pages = Math.ceil(carouselInnerWidth / carouselWindowWidth);
    currentPage = Math.ceil(grid.scrollLeft / carouselWindowWidth);
    updateButtons();
  };

  const navigate = (direction: number) => {
    const nextPage = (currentPage + direction) % pages;
    navigateToPage(nextPage);
  };

  const navigateToPage = (pageNumber: number) => {
    currentPage = pageNumber;
    grid.scrollLeft = pageNumber * carouselWindowWidth;
    updateButtons();
  };

  const calculateAndNavigate = () => {
    calculateDimensions();
    navigateToPage(currentPage);
  };

  const updateButtons = () => {
    prevButton.disabled = currentPage === 0;
    nextButton.disabled = currentPage === pages - 1;
  };

  init();
});
