import { isNotNull } from "./isNotNull.ts";

export const ensureAllElementsNotNull = <
  T extends readonly (unknown | null | undefined)[],
>(
  ...arr: T
): { [K in keyof T]: NonNullable<T[K]> } | null =>
  arr.every(isNotNull)
    ? arr as unknown as { [K in keyof T]: NonNullable<T[K]> }
    : null;
