/// <reference types="./plausibleTypes.d.ts" />

import { logIfDevModeEnabled } from "../web/developerMode.ts";

const log = logIfDevModeEnabled("plausible");

const dummyPlausible: PlausibleEventRecorder = (
  eventName: string,
  props?: PlausibleEventOptions,
) => log(eventName, props);

export const plausibleSendEvent: PlausibleEventRecorder =
  typeof window !== "undefined"
    ? (eventName: string, props?: PlausibleEventOptions) => {
      if (globalThis.plausible && typeof globalThis.plausible === "function") {
        globalThis.plausible(eventName, props);
      }
      dummyPlausible(eventName, props);
    }
    : dummyPlausible;
