import type { Simplify } from "type-fest";
/**
 * Returns a new object containing all specified keys from the original object.
 * If the original object doesn't contain all keys, the missing keys will be set to undefined.
 * **warning**: For convenience, the type _does not_ include the possible `undefined` value;
 * All values are assumed to be found; it is implied that you know for sure they exist, or
 * you'll otherwise check.
 * @param obj The original object
 * @param keys The keys to pick from the original object
 * @returns A new object containing all specified keys
 */
export const pickAll = <T extends Record<K, unknown>, K extends keyof T>(
  obj: T,
  keys: readonly K[],
): Simplify<Pick<T, K>> => {
  return keys.reduce((acc, val) => {
    return (acc[val] = obj[val]), acc;
  }, {} as Simplify<Pick<T, K>>);
};

/**
 * Returns an object containing only the specified keys from the original object.
 * If the passed object contains only part of the keys, only these will be included.
 * If you want to ensure that all keys are present in the returned object, use {@link pickAll}.
 * If you want an error if a key doesn't exist, use Zod.
 * @param obj The original object
 * @param keys The keys to pick from the original object
 * @returns A new object containing only the specified keys
 */
export const pick = <T extends Record<K, unknown>, K extends keyof T>(
  obj: T,
  keys: readonly K[],
): Simplify<Partial<Pick<T, K>>> => {
  return keys.reduce((acc, val) => {
    if (val in obj) {
      acc[val] = obj[val];
    }
    return acc;
  }, {} as Simplify<Partial<Pick<T, K>>>);
};
