import { Signal, type SignalOptions } from "./Signal.ts";
import { identity } from "./identity.ts";

type MapSignalListener<T> = (
  key: keyof T,
  value: T[keyof T],
  oldValue?: T[keyof T],
) => void;
type MapSignalListenerRemovalOrAdditions<T> = (
  key: keyof T,
  value: T[keyof T],
) => void;

interface MapSignal<T> extends Signal<T, T> {
  setItem: (key: keyof T, value: T[keyof T]) => void;
  getItem: (key: keyof T) => T[keyof T];
  hasItem: (key: keyof T) => boolean;
  removeItem: (key: keyof T) => void;
  onKeyAdded: (fn: MapSignalListenerRemovalOrAdditions<T>) => void;
  offKeyAdded: (fn: MapSignalListenerRemovalOrAdditions<T>) => void;
  onKeyRemoved: (fn: MapSignalListenerRemovalOrAdditions<T>) => void;
  offKeyRemoved: (fn: MapSignalListenerRemovalOrAdditions<T>) => void;
  onKeyChanged: (fn: MapSignalListener<T>) => void;
  offKeyChanged: (fn: MapSignalListener<T>) => void;
}

/**
 * Reactive hashmap. Builds on {@link Signal}
 */
export const MapSignal = <T extends Record<string, unknown>>(
  value: T,
  { transform = identity }: SignalOptions<T, T> = {},
): MapSignal<T> => {
  const signal = Signal<T>(value, { transform });

  const listenersForAdditions = new Set<
    MapSignalListenerRemovalOrAdditions<T>
  >();
  const listenersForRemovals = new Set<
    MapSignalListenerRemovalOrAdditions<T>
  >();
  const listenersForChange = new Set<MapSignalListener<T>>();

  const setItem = (key: keyof T, value: T[keyof T]) => {
    const oldData = signal.get();
    const newData = { ...oldData, [key]: value };
    signal.set(newData);
    if (!(key in oldData)) {
      listenersForAdditions.forEach((fn) => fn(key, value));
    } else if (oldData[key] === value) {
      return;
    } else {
      listenersForChange.forEach((fn) => fn(key, value, oldData[key]));
    }
  };

  const getItem = (key: keyof T) => signal.get()[key];

  const hasItem = (key: keyof T) => key in signal.get();

  const removeItem = (key: keyof T) => {
    const oldData = signal.get();
    if (!(key in oldData)) {
      return;
    }
    const { [key]: _delete, ...newData } = oldData;
    listenersForRemovals.forEach((fn) => fn(key, oldData[key] as T[keyof T]));
    signal.set(newData as T);
  };

  const onKeyAdded = (fn: MapSignalListenerRemovalOrAdditions<T>) =>
    listenersForAdditions.add(fn);
  const offKeyAdded = (fn: MapSignalListenerRemovalOrAdditions<T>) =>
    listenersForAdditions.delete(fn);

  const onKeyRemoved = (fn: MapSignalListenerRemovalOrAdditions<T>) =>
    listenersForRemovals.add(fn);
  const offKeyRemoved = (fn: MapSignalListenerRemovalOrAdditions<T>) =>
    listenersForRemovals.delete(fn);

  const onKeyChanged = (fn: MapSignalListener<T>) => listenersForChange.add(fn);
  const offKeyChanged = (fn: MapSignalListener<T>) =>
    listenersForChange.delete(fn);

  return {
    ...signal,
    setItem,
    getItem,
    hasItem,
    removeItem,
    onKeyAdded,
    offKeyAdded,
    onKeyRemoved,
    offKeyRemoved,
    onKeyChanged,
    offKeyChanged,
  };
};
