import type { Signal } from "../any/Signal.ts";
import type { WritableKeysOf } from "type-fest";

type Attribute = WritableKeysOf<Element>;
export interface NodeSignalBindedFunction {
  (node: Text, attributeName?: "textContent"): Text;
  <T extends HTMLElement>(node: T, attributeName?: Attribute): T;
  <T extends Text | HTMLElement>(node: T, attributeName?: Attribute): T;
  __bind: true; // TODO: why did I add this?
}

/**
 * Creates a function that binds a signal to a node's attribute or text content.
 * @param signal - The signal to bind.
 * @param mapper - A function that converts the signal value to a string.
 * @returns A function that binds the signal to a node's attribute or text content.
 */
export const makeNodeSignalBinder = <
  SignalType,
  SignalInput,
  NodeType extends Text | HTMLElement,
>(
  signal: Signal<SignalType, SignalInput>,
  node: NodeType,
  mapper: (node: NodeType, val: SignalType) => void,
): NodeType => {
  mapper(node, signal.get());
  signal.on((v) => {
    mapper(node, v);
  });
  return node;
};
