/**
 * Transforms any input into an `Error` instance.
 * This is useful for ensuring that any error handling code receives an `Error` object.
 */
export const ensureError = <T extends unknown>(error: T): Error => {
  if (error instanceof Error) {
    return error;
  }
  if (typeof error === "string") {
    return new Error(error);
  }

  if (typeof error === "object" && error !== null) {
    try {
      return new Error(JSON.stringify(error));
    } catch (e) {
      return new Error("An error occurred, but it could not be serialized");
    }
  }
  return new Error("An unknown error occurred");
};
