import {
  type AdvancedMechanicsNodeInput,
  h,
  insertHTMLWordBreaksInClassNames,
} from "../clientScript/clientDependencies.ts";

const {
  p,
  span,
  ul,
  li,
  div,
  h4,
  h3,
} = h;

const classPrefix = "nodeFlashCard";

const iconsNamesMap: Record<string, string> = {
  Navigation2D: "NavigationAgent2D",
  Navigation3D: "NavigationAgent3D",
  CSG: "CSGBox3D",
  Light2D: "DirectionalLight2D",
  Light3D: "DirectionalLight3D",
};

const getIconPath = (name: string) => {
  const iconName = iconsNamesMap[name] ?? name;
  return `./icons/godot/${iconName}.svg`;
};

// TODO: image paths and data path are relative. This is fine because this element
// is only used in the Node Flashcard Shuffler, which is on the front page and has a
// known, static path.
// If we ever use this component outside of the shuffler, we need to make the paths
// absolute, by passing a base URL to the component somehow.

export const NodeFlashCard = (
  { category, title, use_when, examples, name }: AdvancedMechanicsNodeInput,
) =>
  li(
    { className: [classPrefix, `${classPrefix}Category-${category}`] },
    div(
      { className: `${classPrefix}Header` },
      h3(
        { className: `${classPrefix}HeaderTitle` },
        insertHTMLWordBreaksInClassNames(name),
      ),
      div({
        className: `${classPrefix}HeaderIcon`,
        style: { "--node-icon": `url(${getIconPath(name)})` },
      }),
    ),
    div(
      { className: `${classPrefix}Body` },
      span({ className: `${classPrefix}Badge` }, category),
      p(
        { className: `${classPrefix}ShortDescription` },
        insertHTMLWordBreaksInClassNames(title),
      ),
      div(
        { className: `${classPrefix}Usage` },
        h4({ className: `${classPrefix}UsageTitle` }, "USE IT WHEN"),
        p(
          { className: `${classPrefix}UsageText` },
          use_when,
        ),
      ),
      div(
        { className: `${classPrefix}Examples` },
        h4({ className: `${classPrefix}ExamplesTitle` }, "EXAMPLES"),
        ul(
          { className: `${classPrefix}ExamplesList`, role: "list" },
          ...examples.map((example) => li(example)),
        ),
      ),
    ),
  );
