import type { GenericFunction } from "../types/GenericFunction.ts";

/**
 * Calls a function when the user stops scrolling.
 * Cleans itself, so you need to call it every time (this isn't an event handler).
 * TODO: maybe use `onscrollend` instead, and provide a polyfill for Safari
 * @param fn - The function to call when the user stops scrolling.
 * @param checkInterval - The interval in milliseconds to check if the user has stopped scrolling.
 * @param root - The root element to listen for scroll events on. Defaults to the global window object.
 */
export const onScrollStopped = (
  fn: GenericFunction,
  checkInterval = 150,
  root?: Node,
): void => {
  let timer = -1;
  const target = root ?? globalThis;
  const onScroll = () => {
    clearTimeout(timer);
    timer = setTimeout(() => {
      fn();
      target.removeEventListener("scroll", onScroll);
    }, checkInterval);
  };
  target.addEventListener("scroll", onScroll, { passive: true });
};
