import { Signal } from "./Signal.ts";
import { assertExhaustiveSwitch } from "./UnreachableCaseError.ts";
import { ensureError } from "./ensureError.ts";

interface ResultSuccess<T> {
  data: T;
  error: null;
  success: true;
  status: "success";
}

interface ResultError {
  data: null;
  error: Error;
  success: false;
  status: "error";
}

interface ResultLoading {
  data: null;
  error: null;
  success: false;
  status: "loading";
}

interface ResultNone {
  data: null;
  error: null;
  success: false;
  status: "none";
}

type Result<T> = ResultSuccess<T> | ResultError | ResultLoading | ResultNone;

interface FetcherSignal<T> extends Signal<Result<T>, Result<T>> {
  /**
   * Loads data from the given URL and updates the signal state.
   * If a request is already in progress or data is already loaded, it will not initiate a new request.
   * Use `reset()` to clear the current state before loading new data.
   *
   * @param url - The URL to fetch data from.
   */
  load: (url: string) => void;
  /**
   * Resets the signal state to its initial value.
   */
  reset: () => FetcherSignal<T>;
  /**
   * Returns the current data from the signal.
   * If the signal is in a "none" state, it will return `null`.
   */
  data: () => T | null;
}

/**
 * @param initialValue - Optional initial value to set the signal state.
 * If provided, the signal will start in a success state with the given data.
 * If not provided, the signal will start in a "none" state. If you want to load data after providing an initial value, use `reset()` before `load()`.
 * @returns
 */
export const FetcherSignal = <T>(initialValue?: T): FetcherSignal<T> => {
  const signal = Signal<Result<T>>(
    initialValue
      ? {
          data: initialValue,
          error: null,
          success: true,
          status: "success",
        }
      : {
          data: null,
          error: null,
          success: false,
          status: "none",
        },
  );

  const load = (url: string) => {
    const currentStatus = signal.get().status;

    if (currentStatus !== "none") {
      switch (currentStatus) {
        case "loading":
          console.warn("Already loading data, ignoring new request.");
          break;
        case "success":
        case "error":
          console.warn("Data already loaded, ignoring new request.");
          break;
        default:
          assertExhaustiveSwitch(currentStatus);
      }
      return;
    }

    signal.set({
      data: null,
      error: null,
      success: false,
      status: "loading",
    });

    fetch(url)
      .then((response) => {
        if (!response.ok) {
          throw new Error(`Failed to fetch ${url}`);
        }
        return response.json();
      })
      .then((data: T) => {
        signal.set({
          data,
          error: null,
          success: true,
          status: "success",
        });
      })
      .catch((error) => {
        signal.set({
          data: null,
          error: ensureError(error),
          success: false,
          status: "error",
        });
      });
  };

  const reset = () => {
    signal.set({
      data: null,
      error: null,
      success: false,
      status: "none",
    });
    return fetcherSignal;
  };

  const data = () => signal.get().data;

  const fetcherSignal = {
    ...signal,
    load,
    reset,
    data,
  };

  return fetcherSignal;
};
