import {
  type DomRelativePosition,
  getElementRelativePosition,
} from "./getElementRelativePosition.ts";
/**
 * Checks if an element is at least partially visible within its scrollable parent
 * @param element - The element to check visibility for
 * @param scrollableParent - The scrollable container element
 * @returns `true` if the element is at least partially visible
 */
export const isElementPartiallyVisibleInParent = (
  element: HTMLElement,
  scrollableParent: HTMLElement,
): boolean => {
  const relative = getElementRelativePosition(element, scrollableParent);

  return isRelativePositionPartiallyWithinParent(relative);
};

export const isRelativePositionPartiallyWithinParent = (
  relative: DomRelativePosition,
): boolean => (relative.bottom > 0 &&
  relative.bottom < relative.parentHeight);
