/**
 * Long class names or composed words can push layouts or get cut off.
 * This function inserts css hyphens if needed.
 *
 * Using `hyphens: auto` works well, but won't cut words that browsers don't
 * have in their dictionaries. (Interestingly, capitalization matters;
 * so make sure you use all lowercase, and use CSS to capitalize).
 *
 * We can insert our own cutoff points with `&shy;`.
 *
 * This function inserts `&shy;` before:
 * - an uppercase letter (if the previous letter was lowercase)
 * - a number (if the previous letter was not a number)
 *
 * https://regexr.com/8l587
 *
 * @param text the text to insert breaks into
 * @returns a text with html elements `&shy;` inserted
 */
export const insertHTMLWordBreaksInClassNames = (text: string) =>
  text.replaceAll(/([^A-Z0-9 .\s]+)([A-Z0-9])/g, "$1&shy;$2");
