// Stateless helper functions used by shader-preview.ts.
// WebGL compilation, color conversion, and uniform management.

import type { ShaderUniformDefaults } from "./shaderGLSL.ts";

type GL = WebGLRenderingContext | WebGL2RenderingContext;
export type ShaderUniformValue = string | number | number[];
export type ShaderUniformValues = Record<string, ShaderUniformValue>;
export type ShaderUniformLocations = Record<string, WebGLUniformLocation | null>;

function compileShader(gl: GL, type: number, source: string): WebGLShader {
  const shader = gl.createShader(type);
  if (!shader) throw new Error("gl.createShader() returned null");
  gl.shaderSource(shader, source);
  gl.compileShader(shader);
  if (!gl.getShaderParameter(shader, gl.COMPILE_STATUS)) {
    const log = gl.getShaderInfoLog(shader) ?? "(no log)";
    gl.deleteShader(shader);
    throw new Error(
      `${
        type === gl.VERTEX_SHADER ? "Vertex" : "Fragment"
      } shader error:\n${log}`,
    );
  }
  return shader;
}

/**
 * Compiles and links a program from vertex and fragment GLSL source.
 */
function buildProgram(
  gl: GL,
  vertexSource: string,
  fragmentSource: string,
): WebGLProgram {
  const vertexShader = compileShader(gl, gl.VERTEX_SHADER, vertexSource);
  const fragmentShader = compileShader(gl, gl.FRAGMENT_SHADER, fragmentSource);
  const program = gl.createProgram();
  if (!program) throw new Error("gl.createProgram() returned null");
  gl.attachShader(program, vertexShader);
  gl.attachShader(program, fragmentShader);
  gl.linkProgram(program);
  gl.deleteShader(vertexShader);
  gl.deleteShader(fragmentShader);
  if (!gl.getProgramParameter(program, gl.LINK_STATUS)) {
    const log = gl.getProgramInfoLog(program) ?? "(no log)";
    gl.deleteProgram(program);
    throw new Error(`Program link error:\n${log}`);
  }
  return program;
}

// '#rrggbb' -> [r, g, b] each in 0..1

/**
 * Transforms a string in the format '#rrggbb' to a [r, g, b] array, each within the 0..1 range.
 * 
 * @param hexString A string in the format '#rrggbb'
 * @returns A [r, g, b] array, each within the 0..1 range.
 */
function hexToRgb(hexString: string): [number, number, number] {
  const packed = Number.parseInt(hexString.replace("#", ""), 16);
  return [
    (packed >> 16 & 255) / 255,
    (packed >> 8 & 255) / 255,
    (packed & 255) / 255,
  ];
}

// Reads initial uniform values from all input[data-uniform] inside container.
// Returns a map of { uniformName -> value } where value is:
//   string  : for type="color" (hex)
//   number[]: for vec2, vec3, vec4 (keyed by data-component index)
//   number  : for floats

/**
 * Used for syncing with the UI input controllers.
 * Reads initial uniform values from all input[data-uniform] inside container.
 * 
 * @param container HTML element containing input fields corresponding to shader uniforms
 * @returns Record of uniform names and their read values
 */
function readUniformValues(container: Element | null): ShaderUniformValues {
  if (!container) return {};
  const uniformValues: ShaderUniformValues = {};
  for (
    const input of container.querySelectorAll<HTMLInputElement>(
      "input[data-uniform]",
    )
  ) {
    const uniformName = input.dataset.uniform!;
    const componentIndex = input.dataset.component;
    if (input.type === "color") {
      uniformValues[uniformName] = input.value;
    } else if (componentIndex === undefined) {
      uniformValues[uniformName] = Number.parseFloat(input.value);
    } else {
      if (!Array.isArray(uniformValues[uniformName])) {
        uniformValues[uniformName] = [];
      }
      (uniformValues[uniformName] as number[])[
        Number.parseInt(componentIndex)
      ] = Number.parseFloat(input.value);
    }
  }
  return uniformValues;
}

// 
/**
 * Wires input event listeners on all input[data-uniform] to keep uniformValues current.
 * 
 * @param container HTML element containing input fields corresponding to shader uniforms
 * @param uniformValues Record of uniform names and their read values
 * @returns 
 */
function wireInputListeners(
  container: Element | null,
  uniformValues: ShaderUniformValues,
): void {
  if (!container) return;
  for (
    const input of container.querySelectorAll<HTMLInputElement>(
      "input[data-uniform]",
    )
  ) {
    const uniformName = input.dataset.uniform!;
    const componentIndex = input.dataset.component;
    input.addEventListener("input", () => {
      if (input.type === "color") {
        uniformValues[uniformName] = input.value;
      } else if (componentIndex === undefined) {
        uniformValues[uniformName] = Number.parseFloat(input.value);
      } else {
        if (!Array.isArray(uniformValues[uniformName])) {
          uniformValues[uniformName] = [];
        }
        (uniformValues[uniformName] as number[])[
          Number.parseInt(componentIndex)
        ] = Number.parseFloat(input.value);
      }
    });
  }
}

/**
 * Uploads all control-driven uniforms to corresponding uniform locations.
 */
function uploadControlUniforms(
  gl: GL,
  uniformLocations: ShaderUniformLocations,
  uniformValues: ShaderUniformValues,
  shaderUniforms: ShaderUniformDefaults,
): void {
  for (const [name, value] of Object.entries(uniformValues)) {
    const location = uniformLocations[name];
    if (!location) continue;
    if (typeof value === "string") {
      const [r, g, b] = hexToRgb(value);
      if (shaderUniforms[name]?.type === "vec4") {
        gl.uniform4f(location, r, g, b, 1.0);
      } else gl.uniform3f(location, r, g, b);
    } else if (Array.isArray(value)) {
      if (value.length === 2) {
        gl.uniform2f(location, value[0] ?? 0, value[1] ?? 0);
      } else {gl.uniform3f(
          location,
          value[0] ?? 0,
          value[1] ?? 0,
          value[2] ?? 0,
        );}
    } else {
      gl.uniform1f(location, value);
    }
  }
}

/**
 * Uploads uniforms that have defaults but no control widget.
 */
function uploadDefaultUniforms(
  gl: GL,
  uniformLocations: ShaderUniformLocations,
  shaderUniforms: ShaderUniformDefaults,
  controlledNames: Set<string>,
): void {
  for (const [name, uniformDefault] of Object.entries(shaderUniforms)) {
    if (controlledNames.has(name)) continue;
    const location = uniformLocations[name];
    if (!location) continue;
    const v = uniformDefault.value;
    switch (uniformDefault.type) {
      case "float":
        gl.uniform1f(location, v[0] ?? 0);
        break;
      case "vec2":
        gl.uniform2f(location, v[0] ?? 0, v[1] ?? 0);
        break;
      case "vec3":
        gl.uniform3f(location, v[0] ?? 0, v[1] ?? 0, v[2] ?? 0);
        break;
      case "vec4":
        gl.uniform4f(location, v[0] ?? 0, v[1] ?? 0, v[2] ?? 0, v[3] ?? 0);
        break;
    }
  }
}

function rgbToHex([r = 0, g = 0, b = 0]: number[]): string {
  return "#" + [r, g, b]
    .map((v) => Math.round(v * 255).toString(16).padStart(2, "0"))
    .join("");
}

export const shaderHelpers = {
  buildProgram,
  hexToRgb,
  readUniformValues,
  wireInputListeners,
  uploadControlUniforms,
  uploadDefaultUniforms,
  rgbToHex
}