/**
 * Shortcut for Object.getPrototypeOf
 */
export const protoOf: (a: unknown) => object = Object.getPrototypeOf;

/**
 * Object prototype, use it for comparisons
 */
export const objProto = protoOf({});

/**
 * Checks if a value is a plain object.
 * TODO: Check if this version or `isPlainObject` is more accurate.`
 */
export const isObject = (value: unknown): value is Record<string, unknown> =>
  typeof value === "object" && protoOf(value) === objProto;
