// Translates gdshader source to GLSL ES 1.0 or 3.00 strings.
// TODO: If more built-in uniforms are needed, add them to the preambles below.

const FRAG_PREAMBLE_GL1 = `precision mediump float;

uniform sampler2D uTexture;
uniform float uTime;
uniform vec2 uTexturePixelSize;
uniform vec2 uScreenPixelSize;

varying vec2 vUV;

#define TEXTURE             uTexture
#define UV                  vUV
#define TIME                uTime
#define TEXTURE_PIXEL_SIZE  uTexturePixelSize
#define SCREEN_PIXEL_SIZE   uScreenPixelSize
#define FRAGCOORD           gl_FragCoord
#define COLOR               gl_FragColor
#define PI                  3.14159265358979323846
#define TAU                 6.28318530717958647692
#define E                   2.71828182845904523536
`;

const FRAG_PREAMBLE_GL2 = `#version 300 es
precision mediump float;

uniform sampler2D uTexture;
uniform float uTime;
uniform vec2 uTexturePixelSize;
uniform vec2 uScreenPixelSize;

in vec2 vUV;
out vec4 fragColor;

#define TEXTURE             uTexture
#define UV                  vUV
#define TIME                uTime
#define TEXTURE_PIXEL_SIZE  uTexturePixelSize
#define SCREEN_PIXEL_SIZE   uScreenPixelSize
#define FRAGCOORD           gl_FragCoord
#define COLOR               fragColor
#define PI                  3.14159265358979323846
#define TAU                 6.28318530717958647692
#define E                   2.71828182845904523536
`;

const VERT_SRC_GL1 = `
attribute vec2 aPosition;
attribute vec2 aUV;
varying vec2 vUV;
void main() {
  vUV = aUV;
  gl_Position = vec4(aPosition, 0.0, 1.0);
}
`;

const VERT_SRC_GL2 = `#version 300 es
in vec2 aPosition;
in vec2 aUV;
out vec2 vUV;
void main() {
  vUV = aUV;
  gl_Position = vec4(aPosition, 0.0, 1.0);
}
`;

/**
 * Removes a top-level `void <name>() { ... }` block from source.
 * 
 * @param source Source string containing the function
 * @param name The name of the function to remove
 * @returns 
 */
function stripFunction(source: string, name: string): string {
  const pattern = new RegExp(String.raw`void\s+${name}\s*\(\s*\)\s*\{`);
  const match = pattern.exec(source);
  if (!match) return source;
  let depth = 0;
  let i = match.index + match[0].length - 1;
  while (i < source.length) {
    if (source[i] === "{") depth++;
    else if (source[i] === "}") {
      depth--;
      if (depth === 0) {
        return source.slice(0, match.index) + source.slice(i + 1);
      }
    }
    i++;
  }
  return source;
}

/**
 * Translates gdshader source to GLSL.
 * 
 * @param source 
 * @param gl2 When true, selects GLSL ES 3.00 (WebGL2); defaults to false, which selects GLSL ES 1.0 (WebGL1) 
 * @returns 
 */
export function gdshaderToGLSL(source: string, gl2 = false): string {
  let s = source;
  s = s.replace(/shader_type\s+\w+\s*;/g, "");
  s = s.replace(/render_mode\s+[^;]+;/g, "");
  // Strip Godot uniform hints and defaults: `uniform float u : hint_range(0,1) = 0.5;` -> `uniform float u;`
  s = s.replace(/(uniform\s+\w+\s+\w+)\s*(?::[^=;\n]+)?(?:=[^;\n]+)?;/g, "$1;");
  if (/void\s+fragment\s*\(\s*\)/.test(s)) {
    s = s.replace(/void\s+fragment\s*\(\s*\)/, "void main()");
  } else {
    s = `void main() {\n${s}\n}`;
  }
  s = stripFunction(s, "vertex");
  if (!gl2) s = s.replace(/\btexture\s*\(/g, "texture2D(");
  return (gl2 ? FRAG_PREAMBLE_GL2 : FRAG_PREAMBLE_GL1) + "\n" + s;
}

export function getVertexSrc(gl2 = false): string {
  return gl2 ? VERT_SRC_GL2 : VERT_SRC_GL1;
}

