import { isHTMLBooleanAttribute } from "./htmlBooleanAttributes.ts";
import type { HTMLFactory } from "./types.ts";
import { kebabize } from "../kebabize.ts";
import { escapeHTML } from "../escapeHTML.ts";
import { isObject } from "../isObject.ts";

/**
 * Creates a DOM element with the given tag name, attributes, and children.
 *
 * @param tagName The tag name of the element to create.
 * @param attributes The attributes to set on the element.
 * @param children The children to append to the element.
 * @returns The created element.
 */
export const createElementDom: HTMLFactory.CreateElement<"client"> = <
  K extends keyof HTMLElementTagNameMap,
>(
  tagName: K,
  ...props: (HTMLFactory.Attributes<K> | null | HTMLFactory.ValidChild)[]
) => {
  const element = document.createElement(tagName);
  const [attributes, ...children] = (
    isObject(props[0] || props[0] == null) ? props : [null, ...props]
  ) as [HTMLFactory.Attributes<K> | null, ...HTMLFactory.ValidChild[]];
  attributes &&
    Object.entries(attributes).forEach(([k, v]) => {
      if (typeof v === "function") {
        const fn = v as
          | HTMLFactory.BindedFunction
          | EventListenerOrEventListenerObject;
        if (k.startsWith("on")) {
          const listener = fn as EventListenerOrEventListenerObject;
          const event = k.slice(2).toLowerCase();
          element.addEventListener(event, listener);
        } else {
          // @ts-expect-error: way too complicated to type properly
          fn(element, k);
        }
      } else if (k.startsWith("aria")) {
        const property = "aria-" + kebabize(k.slice(4));
        element.setAttribute(property, v + "");
      } else if (k.startsWith("data")) {
        if (v === null) {
          return;
        }
        const property = "data-" + kebabize(k.slice(4));
        element.setAttribute(property, v + "");
      } else if (k === "acceptCharset") {
        return `accept-charset="${escapeHTML(v + "")}"`;
      } else if (k === "colorScheme") {
        return `color-scheme="${escapeHTML(v + "")}"`;
      } else if (k === "themeColor") {
        return `theme-color="${escapeHTML(v + "")}"`;
      } else if (k === "httpEquiv") {
        return `http-equiv="${escapeHTML(v + "")}"`;
      } else if (k === "className" || k === "class") {
        const classValue = v as HTMLFactory.ClassNameValue;
        if (classValue == null || classValue === false) {
          return;
        }
        if (Array.isArray(classValue)) {
          // If I use the more appropriate `@ts-expect-error`, ts will sometimes complain that the annation is useless, because it can totally infer the type
          // but if I remove it, it will sometimes complain that the type is infinitely deep.
          //@ts-ignore typescript can't handle infinity... sometimes.
          const classes = classValue.flat(Infinity).filter(Boolean) as string[];
          element.classList.add(...classes);
        } else {
          if (classValue.includes(" ")) {
            throw new Error("Invalid class name: " + v);
          }
          element.classList.add(v + "");
        }
      } else if (k === "props") {
        const propsValue = v as HTMLFactory.Props;
        Object.entries(propsValue).forEach(([prop, value]) => {
          // TODO: properly type props
          // @ts-expect-error: this is an escape hatch
          element[prop] = value;
        });
      } else if (v === false && isHTMLBooleanAttribute(k)) {
        return;
      } else if (k === "style") {
        if (v == null || v === false) {
          return;
        }
        if (typeof v === "string") {
          element.setAttribute("style", escapeHTML(v));
        } else {
          const styleValue = v as Partial<CSSStyleDeclaration>;
          return Object.entries(styleValue).forEach(([prop, value]) =>
            element.style.setProperty(prop, value + "")
          );
        }
      } else if (v === null) {
        return;
      } else {
        element.setAttribute(k, v + "");
      }
    });
  children &&
    children.forEach(
      (c) => {
        if (c == null || c === false) {
          return;
        }
        if (Array.isArray(c)) {
          element.append(
            createElementDom(...c as Parameters<typeof createElementDom>),
          );
          return;
        }
        if (typeof c === "string") {
          element.innerHTML = c;
          return;
        }
        if (typeof c === "number" || typeof c === "boolean") {
          element.innerHTML = c.toLocaleString();
          return;
        }
        if (typeof c === "function") {
          element.innerHTML = "";
          const textContent = c(document.createTextNode(""), "textContent");
          if (textContent) {
            element.appendChild(textContent);
          }
          return;
        }
        if (typeof c === "object") {
          if ("rawHTML" in c && "escape" in c && c.escape === true) {
            element.append(document.createTextNode(c.rawHTML + ""));
            return;
          } else if ("nodeType" in c) {
            element.append(c);
            return;
          }
          console.log("Unexpected object type:", c);
        }
        element.innerHTML = c.toString();
        return;
      },
    );
  return element;
};
