import { createElementDom } from "./createElementDom.web.ts";
import { createElementsProxy } from "./createElementProxy.ts";

export const appendChildren = (parent: HTMLElement, ...children: Child[]) => {
  (children as ChildScalar[]).flat(Infinity).forEach((child) => {
    if (child == null || child === false) {
      return;
    }
    parent.append(child);
  });
};

export const clearAllChildren = (parent: HTMLElement) => {
  while (parent.firstChild) {
    parent.firstChild.remove();
  }
};

export const replaceAllChildren = (
  parent: HTMLElement,
  ...children: Child[]
) =>
  parent.replaceChildren(
    ...(children as ChildScalar[]).flat(Infinity) as Node[],
  );

export const markAsNeedToEscape = (rawHTML: string) => ({rawHTML, escape: true});

export const h = createElementsProxy(createElementDom, {
  add: appendChildren,
  clear: clearAllChildren,
  replace: replaceAllChildren,
  escape: markAsNeedToEscape,
});

type ChildScalar = Node | string | undefined | null | false;
type Child = ChildScalar | ChildScalar[] | Child[];
