import { processDomElementOnce } from "../clientScript/clientDependencies.ts";

const classPrefix = ".betaMention";

processDomElementOnce(classPrefix, (element: HTMLElement) => {
  const button = element.querySelector("button");
  const message = element.querySelector("p");

  if (button && message) {
    button.addEventListener("click", () => {
      element.classList.toggle("closed");
      localStorage.setItem(
        "betaMentionClosed",
        element.classList.contains("closed") ? "true" : "false",
      );
    });
  }

  // On load, check if the mention was closed before
  const wasClosed = localStorage.getItem("betaMentionClosed");
  if (wasClosed === "true") {
    element.classList.add("closed");
  }
});
