import { DEV_MODE } from "./env.ts";
import { cleanupUrlString } from "../../toolbox/any/cleanupUrlString.ts";

const fakeResponse = <T>(arg: T) =>
  new Promise<T>((ok) => setTimeout(ok, 100, arg));

export const API = DEV_MODE
  ? (_base = "") => ({
    claps: {
      async add(amount: number, url: string) {
        console.log("api:claps:add", { amount, url });
        return await fakeResponse({});
      },
      async get(url: string) {
        console.log("api:claps:get", { url });
        return await fakeResponse(0);
      },
    },
    newsletter: {
      async subscribe(email: string, name: string) {
        console.log("api:newsletter:subscribe", { email, name });
        return await fakeResponse({});
      },
    },
  })
  : (base = "https://api.gdquest.com/1") => ({
    claps: {
      async add(amount: number, url: string) {
        const response = await fetch(
          `${base}/claps/add/${amount}/${cleanupUrlString(url)}`,
        );
        return await response.json();
      },
      async get(url: string): Promise<number> {
        const response = await fetch(
          `${base}/claps/get/${cleanupUrlString(url)}`,
        );
        const data = await response.json();
        if (typeof data !== "number") {
          if ("message" in data && data.message) {
            throw new Error(data.message);
          }
          throw new Error(
            "Invalid response from claps API " + JSON.stringify(data),
          );
        }
        return data;
      },
    },
    newsletter: {
      async subscribe(email: string, name: string) {
        const formData = new FormData();
        formData.append("email", email);
        formData.append("name", name);
        formData.append("json", "true");
        const response = await fetch(
          `${base}/newsletter`,
          {
            method: "POST",
            body: formData,
          },
        );
        return await response.json();
      },
    },
  });
