type SuggestionsDropdownConfig = {
  classPrefix: string;
  container: HTMLDivElement;
  input: HTMLInputElement;
  onSelect: (value: string) => void;
};

type SuggestionsDropdownController = {
  render: (items: string[]) => void;
  clear: () => void;
  handleKey: (event: KeyboardEvent) => boolean;
};

const createId = (prefix: string) =>
  `${prefix}-${Math.random().toString(36).slice(2)}`;

export const createSuggestionsDropdown = ({
  classPrefix,
  container,
  input,
  onSelect,
}: SuggestionsDropdownConfig): SuggestionsDropdownController => {
  let suggestions: string[] = [];
  let highlightedIndex = -1;
  let buttons: HTMLButtonElement[] = [];
  let justSelected = false;
  const activeClass = `${classPrefix}SuggestionActive`;

  container.hidden = true;
  container.setAttribute("role", "presentation");

  const listId = createId(`${classPrefix}SuggestionsList`);
  const list = document.createElement("ul");
  list.className = `${classPrefix}SuggestionsList`;
  list.id = listId;
  list.setAttribute("role", "listbox");
  list.setAttribute("aria-label", "Search suggestions");
  container.append(list);

  input.setAttribute("aria-controls", listId);
  input.setAttribute("aria-expanded", "false");
  input.setAttribute("aria-autocomplete", "list");
  input.setAttribute("role", "combobox");
  input.setAttribute("aria-haspopup", "listbox");

  const optionIdPrefix = createId(`${classPrefix}SuggestionOption`);

  const clear = () => {
    suggestions = [];
    highlightedIndex = -1;
    buttons = [];
    list.textContent = "";
    container.hidden = true;
    input.setAttribute("aria-expanded", "false");
    input.removeAttribute("aria-activedescendant");
  };

  const select = (index: number) => {
    const suggestion = suggestions[index];
    if (!suggestion) return;
    // Suppress the "input" event re-render triggered by programmatic value
    // assignment — Firefox mobile fires "input" on value= whereas Chrome does not.
    justSelected = true;
    input.value = suggestion;
    onSelect(suggestion);
    clear();
  };

  const setHighlighted = (index: number) => {
    highlightedIndex = index;
    buttons.forEach((button, idx) => {
      const isActive = idx === highlightedIndex;
      button.classList.toggle(activeClass, isActive);
      button.setAttribute("aria-selected", String(isActive));
    });
    const activeButton = buttons[highlightedIndex];
    if (activeButton) {
      input.setAttribute("aria-activedescendant", activeButton.id);
    } else {
      input.removeAttribute("aria-activedescendant");
    }
  };

  const render = (items: string[]) => {
    if (items.length === 0) {
      clear();
      return;
    }
    if (justSelected) {
      justSelected = false;
      return;
    }
    suggestions = items;
    highlightedIndex = -1;
    buttons = [];
    list.textContent = "";
    container.hidden = false;
    input.setAttribute("aria-expanded", "true");

    for (const [index, suggestion] of suggestions.entries()) {
      const entry = document.createElement("li");
      entry.className = `${classPrefix}Suggestion`;
      entry.setAttribute("role", "presentation");

      const button = document.createElement("button");
      button.type = "button";
      button.className = `${classPrefix}SuggestionButton`;
      button.id = `${optionIdPrefix}-${index}`;
      button.setAttribute("role", "option");
      button.setAttribute("aria-selected", "false");
      button.textContent = suggestion;
      button.addEventListener("mousedown", (e) => e.preventDefault());
      button.addEventListener("click", () => select(index));

      entry.append(button);
      list.append(entry);
      buttons.push(button);
    }
  };

  const handleKey = (event: KeyboardEvent) => {
    if (buttons.length === 0) return false;

    if (event.key === "ArrowDown") {
      setHighlighted((highlightedIndex + 1) % buttons.length);
      return true;
    }
    if (event.key === "ArrowUp") {
      setHighlighted((highlightedIndex - 1 + buttons.length) % buttons.length);
      return true;
    }
    if (event.key === "Enter" && highlightedIndex >= 0) {
      select(highlightedIndex);
      return true;
    }
    if (event.key === "Escape") {
      clear();
      return true;
    }
    return false;
  };

  document.addEventListener("click", (event) => {
    const target = event.target as Node;
    if (!container.contains(target) && target !== input) {
      clear();
    }
  });

  return { render, clear, handleKey };
};
