export const setDeveloperMode = (nameSpace: string, enabled: boolean) => {
  if (typeof window !== "undefined") {
    localStorage.setItem(
      `developerMode:${nameSpace}`,
      enabled ? "true" : "false",
    );
    console.log(
      `Developer mode ${enabled ? "enabled" : "disabled"} for: ${nameSpace}`,
    );
  }
};

export const isDeveloperModeEnabled = (nameSpace: string) => {
  if (typeof window !== "undefined") {
    return localStorage.getItem(`developerMode:${nameSpace}`) === "true" ||
      localStorage.getItem(`developerMode:*`) === "true";
  }
  return false;
};

const consoleCommand = (nameSpace: string, enabled?: boolean) => {
  if (nameSpace == null || enabled == null) {
    console.log(getAvailableNameSpaces());
  } else {
    setDeveloperMode(nameSpace, enabled);
  }
};

export const augmentWindowWithDeveloperMode = () => {
  if (typeof window !== "undefined" && !("devMode" in globalThis)) {
    // @ts-expect-error we are augmenting the global object with a new property
    globalThis.devMode = consoleCommand;
    for (const nameSpace of getAvailableNameSpaces()) {
      if (localStorage.getItem(`developerMode:${nameSpace}`) === "true") {
        console.log(`Developer mode enabled for: ${nameSpace}`);
      }
    }
  }
};

const getAvailableNameSpaces = () => {
  if (typeof window === "undefined") {
    return [];
  }
  const results = [];
  for (const key in localStorage) {
    if (key.startsWith("developerMode:")) {
      const nameSpace = key.replace("developerMode:", "");
      results.push(nameSpace);
    }
  }
  return results;
};

export const logIfDevModeEnabled = (
  nameSpace: string,
) => {
  if (typeof window !== "undefined") {
    if (localStorage.getItem(`developerMode:${nameSpace}`) == null) {
      localStorage.setItem(`developerMode:${nameSpace}`, "false");
    }
  }
  return <T>(arg: T, ...args: unknown[]): T => {
    if (isDeveloperModeEnabled(nameSpace)) {
      console.log(`[${nameSpace}]`, arg, ...args);
    }
    return arg;
  };
};
