import {
  getClampedRandomInt,
  h,
  makeNodeSignalBinder,
  Signal,
  wait,
} from "../clientScript/clientDependencies.ts";
import { createConfetti } from "./clapsButton.client.ts";

const baseClass = "clapsGame";
const { button, span, div, add, h4 } = h;

function dragElement(elmnt: HTMLElement) {
  let pos1 = 0, pos2 = 0, pos3 = 0, pos4 = 0;
  const draggable = elmnt.querySelector<HTMLElement>("[data-is-draghandle]") ||
    elmnt;

  // otherwise, move the DIV from anywhere inside the DIV:
  draggable.addEventListener("mousedown", dragMouseDown);

  function dragMouseDown(e: MouseEvent) {
    e.preventDefault();
    // get the mouse cursor position at startup:
    pos3 = e.clientX;
    pos4 = e.clientY;
    document.onmouseup = closeDragElement;
    // call a function whenever the cursor moves:
    document.onmousemove = elementDrag;
  }

  function elementDrag(e: MouseEvent) {
    e.preventDefault();
    // calculate the new cursor position:
    pos1 = pos3 - e.clientX;
    pos2 = pos4 - e.clientY;
    pos3 = e.clientX;
    pos4 = e.clientY;
    // set the element's new position:
    elmnt.style.top = (elmnt.offsetTop - pos2) + "px";
    elmnt.style.left = (elmnt.offsetLeft - pos1) + "px";
  }

  function closeDragElement() {
    // stop moving when mouse button is released:
    document.onmouseup = null;
    document.onmousemove = null;
  }

  return elmnt;
}

const _startGame = () => {
  const claps = Signal(0);
  const cursors = Signal(0);
  const clapsPerClick = Signal(0);
  const shown = Signal(false);

  const upgradesAvailable = [
    {
      name: "Cursors",
      description: "clicks once per second",
      cost: 20,
      className: "cursor",
      signal: cursors,
    },
    {
      name: "Strength",
      description: "Each click gives you more claps",
      cost: 100,
      className: "strength",
      signal: clapsPerClick,
    },
  ];

  const mainButton = makeNodeSignalBinder(
    claps,
    button(
      {
        class: `${baseClass}ClapsButton`,
        onclick: () => {
          claps.set(claps.get() + 1);
          mainButton.setAttribute("aria-pressed", "true");
          setTimeout(() => {
            mainButton.removeAttribute("aria-pressed");
          }, 500);
        },
      },
      makeNodeSignalBinder(claps, span(), (node, val) => {
        node.textContent = `${val}`;
      }),
    ),
    (node) => {
      node.append(createConfetti());
    },
  );

  const incrementLater = (delay: number) =>
    wait(delay)().then(() => mainButton.click());

  const makeCursor = (index: number) => {
    const clicker = span({
      class: `${baseClass}MainClicker`,
      style: { "--index": index },
    });

    setInterval(() => {
      clicker.style.setProperty("--offset", "0");
      wait(200)().then(() => {
        const increment = 1 + clapsPerClick.get();
        const promises = [];
        for (let j = 0; j < increment; j++) {
          const delay = getClampedRandomInt(100, 50);
          promises.push(() => incrementLater(delay));
        }
        promises.reduce((acc: Promise<unknown>, promise) => {
          return acc.then(promise);
        }, Promise.resolve()).then(() => {
          clicker.style.removeProperty("--offset");
        });
      });
    }, 3000 * (1 + index));

    return clicker;
  };

  add(
    document.body,
    makeNodeSignalBinder(
      shown,
      dragElement(div(
        { class: `${baseClass}Panel` },
        h4(
          { class: `${baseClass}Title`, dataIsDraghandle: true },
          "Claps Clicker",
        ),
        div(
          { class: `${baseClass}Body` },
          div(
            { class: `${baseClass}Main` },
            makeNodeSignalBinder(
              cursors,
              div({ class: `${baseClass}MainClickersContainer` }),
              (node, value) => {
                const existingClickers = node.querySelectorAll(
                  `.${baseClass}MainClicker`,
                ).length || 0;
                for (let i = existingClickers; i < value; i++) {
                  add(node, makeCursor(i));
                }
                node.style.setProperty("--clickers", value.toString());
              },
            ),
            mainButton,
          ),
          div(
            { class: `${baseClass}UpgradesContainer` },
            ...upgradesAvailable.map((
              { name, description, cost, className, signal },
            ) =>
              makeNodeSignalBinder(
                claps,
                button(
                  {
                    class: [
                      `${baseClass}Upgrade`,
                      `${baseClass}Upgrade-${className}`,
                    ],
                    title: description,
                  },
                  span({ class: `${baseClass}UpgradeName` }, name),
                  span({ class: `${baseClass}UpgradeCost` }, cost),
                ),
                (node, val) => {
                  node.disabled = val < cost;
                  node.onclick = () => {
                    claps.set(val - cost);
                    signal.set(signal.get() + 1);
                  };
                },
              )
            ),
          ),
        ),
        button({
          class: `${baseClass}CloseButton`,
          onclick: () => {
            shown.set(false);
          },
        }, span("close panel")),
      )),
      (node, value) => {
        if (value) {
          node.style.removeProperty("display");
        } else {
          node.style.setProperty("display", "none");
        }
      },
    ),
  );

  return shown;
};

let showGame: Signal<boolean, boolean> | null = null;

export const startGame = () => {
  if (!showGame) {
    showGame = _startGame();
  }
  showGame.set(true);
};
