import type { Logger } from "../types/Logger.ts";

interface SimpleConsoleMethods extends Logger {
  log<T>(arg: T, ...args: unknown[]): T;
  debug<T>(arg: T, ...args: unknown[]): T;
  error<T>(arg: T, ...args: unknown[]): T;
  info<T>(arg: T, ...args: unknown[]): T;
  warn<T>(arg: T, ...args: unknown[]): T;
  trace<T>(arg: T, ...args: unknown[]): T;
  assert<T>(condition: boolean, arg: T, ...args: unknown[]): T;
  table<T>(data: T, columns?: string[]): T;
  getLogger(name: string, color?: string): SimpleConsoleMethods;
}

const SimpleConsole = (
  title: string,
  color: string,
): SimpleConsoleMethods => {
  const prefix = title && color
    ? [`%c[${title}]`, `color:${color ?? "#5b5bdf"};`]
    : title
    ? [`%c[${title}]`]
    : [];
  return ({
    log<T>(arg: T, ...args: unknown[]) {
      if (!isModuleEnabled(title)) return arg;
      console.log(...prefix, arg, ...args);
      return arg;
    },
    debug<T>(arg: T, ...args: unknown[]) {
      if (!isModuleEnabled(title)) return arg;
      console.debug(...prefix, arg, ...args);
      return arg;
    },
    error<T>(arg: T, ...args: unknown[]) {
      if (!isModuleEnabled(title)) return arg;
      console.error(...prefix, arg, ...args);
      return arg;
    },
    info<T>(arg: T, ...args: unknown[]) {
      if (!isModuleEnabled(title)) return arg;
      console.info(...prefix, arg, ...args);
      return arg;
    },
    warn<T>(arg: T, ...args: unknown[]) {
      if (!isModuleEnabled(title)) return arg;
      console.warn(...prefix, arg, ...args);
      return arg;
    },
    assert<T>(condition: boolean, arg: T, ...args: unknown[]) {
      if (!isModuleEnabled(title)) return arg;
      console.assert(condition, ...prefix, arg, ...args);
      return arg;
    },
    trace<T>(arg: T, ...args: unknown[]) {
      if (!isModuleEnabled(title)) return arg;
      console.trace(...prefix, arg, ...args);
      return arg;
    },
    table<T>(data: T, columns?: string[]) {
      if (!isModuleEnabled(title)) return data;
      console.table(data, columns);
      return data;
    },
    getLogger(subTitle: string, color = DEFAULT_COLOR) {
      return getOrMakeLogger(
        title && title !== "*" ? `${title}/${subTitle}` : subTitle,
        color,
      );
    },
  });
};

const parseModules = (modules: string) =>
  modules.split(",").reduce((receiver: Set<string>, k: string) => {
    const name = k.trim();
    if (name) receiver.add(name);
    return receiver;
  }, new Set());

const LOG_KEY = "__log__";
const DEFAULT_COLOR = "#5b5bdf";

let defaults = "";

const getEnabledModules = () =>
  parseModules([
    (globalThis.location?.search &&
      new URLSearchParams(globalThis.location.search).get("debug")) ?? "",
    globalThis.localStorage?.getItem(LOG_KEY) ?? "",
    defaults,
  ].join(","));

let enabledModules = new Set<string>();

const isModuleEnabled = (title: string) => {
  if (enabledModules.has("*") || enabledModules.has(title)) {
    return true;
  }
  for (const m of enabledModules) {
    if (title.startsWith(m + "/")) {
      return true;
    }
  }
  return false;
};

/**
 * Refreshes the list of enabled modules based on the given query string.
 * Re-reads the url query string and localStorage too.
 */
const refreshEnabledModules = () => {
  enabledModules = getEnabledModules();
};

/**
 * Toggles the given module in localStorage and refreshes the enabled modules.
 */
const toggleWithLocalStorage = (title: string, toggle: boolean) => {
  if (globalThis.localStorage) {
    const existingValue = parseModules(
      globalThis.localStorage.getItem(LOG_KEY) ?? "",
    );

    if (toggle === false) {
      existingValue.delete(title);
    } else {
      existingValue.add(title);
    }
    globalThis.localStorage.setItem(LOG_KEY, [...existingValue].join(","));
    refreshEnabledModules();
  }
};

const cache: Map<string, SimpleConsoleMethods> = new Map();

const getOrMakeLogger = (title: string, color: string) => {
  if (cache.has(title)) return cache.get(title)!;
  const logger = SimpleConsole(title, color);
  cache.set(title, logger);
  return logger;
};

/**
 * Creates a group of loggers that can be individually turned off or on.
 * This is intended as a client-first logger, to print human-readable log messages to the browser console.
 *
 * For more serious logging, look towards {@link getLogger}
 *
 * Each logger can be enabled or disabled based on:
 * - a parameter passed to the function (`module1,module2`).
 * - the URL parameters (`https://....?debug=module1,module2`).
 * - localStorage (the key is `__log__`, the value is `module1,module2`).
 *
 * Priority goes:
 * The parameter, then the URL parameters, and finally LocalStorage.
 *
 * **note**: the parameter is global to the entire application. It's intended that `simpleModuleLogger` is called once per application.
 *
 * That should be fine because this logger is a client-first logger; the parameter exists only as a fallback in case the logger is used server-side.
 *
 * When creating loggers, use the module name as the title:
 * ```ts ignore
 * const makeLogger = simpleModuleLogger();
 * const logger = makeLogger("module1");
 *
 * logger.log("This is a log message for module1");
 * ```
 * Loggers can have children loggers:
 * ```ts ignore
 * const childLogger = logger.getLogger("child");
 * childLogger.log("This is a log message for module1/child");
 * ````
 * If you enable `module1` (e.g, `debug=module1`), all children will be enabled as well.
 * But if you enable `module1/child` (e.g, `debug=module1/child`), only that child will be enabled.
 *
 * Logger methods don't use `this` internally, and return the first argument. This makes them suitable for use in fluid APIs or promises.
 *
 * e.g:
 * ```ts ignore
 * const { log } = makeLogger("module1");
 * doSomething().then(log).then(...);
 * ````
 */
export const getSimpleModuleLogger = (query = "") => {
  defaults = query;
  enabledModules = getEnabledModules();

  const rootLogger = getOrMakeLogger("*", DEFAULT_COLOR);

  return rootLogger.getLogger;
};

/**
 * Toggles the enabled state of a module.
 *
 * For debugging purposes, you may move this command to global scope:
 * ```ts ignore
 * declare global {
 *   interface Window {
 *     toggleLog: typeof simpleModuleLogger.toggle;
 *   }
 * }
 *
 * globalThis.toggleLog = simpleModuleLogger.toggle;
 * ```
 *
 * @param title The module title to toggle.
 * @param toggle Whether to enable or disable the module.
 */
getSimpleModuleLogger.toggle = toggleWithLocalStorage;
/**
 * Refreshes the list of enabled modules from local storage or the url.
 */
getSimpleModuleLogger.refresh = refreshEnabledModules;
