import {
  autoFetchWhenSubmit,
  type MailSubscriptionRequestFormResponse,
  processDomElementOnce,
} from "../clientScript/clientDependencies.ts";

processDomElementOnce(
  `form[data-is="mailingListCollector"]`,
  (form: HTMLFormElement) => {
    const messagesContainer = form.querySelector<HTMLElement>("[aria-live]");
    if (!messagesContainer) {
      console.error(`there's no announcement field in this mailing list form`);
      return;
    }
    const messages = Array.from(messagesContainer.querySelectorAll("span"));
    if (messages.length < 3) {
      console.error(`missing message elements in this mailing list form`);
      return;
    }
    const [messageAlreadySubscribed, messageSuccess, messageError] = messages
      .map((element) => {
        const newElement = element.cloneNode(true) as HTMLSpanElement;
        newElement.removeAttribute("aria-hidden");
        newElement.removeAttribute("hidden");
        newElement.textContent = element.textContent;
        element.remove();
        return () => {
          messagesContainer.innerHTML = "";
          messagesContainer.append(newElement);
        };
      });
    const jsonInput = form.querySelector<HTMLInputElement>(
      'input[type="hidden"][name="json"]',
    );
    if (jsonInput) {
      jsonInput.value = "true";
    }
    const onSubmit = autoFetchWhenSubmit({
      method: "POST",
      doDisableForm: true,
      doReEnableForm: 500,
      callback: async (err, result) => {
        if (err || !result) {
          console.error(err, result);
          messageError();
          return;
        }
        const data = await result.json() as MailSubscriptionRequestFormResponse;
        switch (data.code) {
          case 200:
            messageAlreadySubscribed();
            break;
          case 201:
            messageSuccess();
            break;
          default:
            messageError();
        }
      },
    });
    form.addEventListener("submit", onSubmit);
  },
);
